"use client";

import * as React from "react";

import { cn } from "@/lib/utils";

import {
  createMatrixSourceAdapter,
  createMatrixSourceSampleError,
  type MatrixSourceAdapter,
} from "./sources";
import { createLuminanceMapper } from "./transforms";
import type {
  MatrixEffectError,
  MatrixEffectHandle,
  MatrixEffectProps,
  MatrixEffectStatus,
  MatrixFrame,
  MatrixFrameContext,
  MatrixFrameRate,
  MatrixGridConfig,
  MatrixReducedMotion,
  MatrixRenderer,
  MatrixSignalMapper,
  MatrixSignalTransform,
  MatrixSource,
} from "./types";

const DEFAULT_CELL_SIZE = 10;
const DEFAULT_CELL_ASPECT_RATIO = 1;
const DEFAULT_MAX_CELLS = 10_000;
const DEFAULT_MAX_DPR = 2;
const DEFAULT_FRAME_RATE: MatrixFrameRate = "auto";
const DEFAULT_REDUCED_MOTION: MatrixReducedMotion = "freeze";
const MAX_BACKING_STORE_PIXELS = 4_194_304;
const MAX_BACKING_STORE_DIMENSION = 16_384;
const LARGE_GRID_WARNING_THRESHOLD = 100_000;
const MAX_PLAYBACK_DELTA_MS = 100;
const FRAME_GATE_EPSILON_MS = 0.5;
const ADAPTIVE_EMA_TIME_CONSTANT_MS = 1_000;
const ADAPTIVE_MISSED_RAF_THRESHOLD_MS = 25;
const ADAPTIVE_DOWNGRADE_COST_MS = 12;
const ADAPTIVE_DOWNGRADE_MISS_EMA = 0.2;
const ADAPTIVE_DOWNGRADE_SUSTAIN_MS = 2_000;
const ADAPTIVE_UPGRADE_COST_MS = 8;
const ADAPTIVE_UPGRADE_MISS_EMA = 0.05;
const ADAPTIVE_UPGRADE_SUSTAIN_MS = 10_000;
const ADAPTIVE_UPGRADE_COOLDOWN_MS = 20_000;
const OFFSCREEN_ROOT_MARGIN = "128px 0px";
const TRANSPARENT_FILL = "rgba(0, 0, 0, 0)";
const EMPTY_RGBA = new Uint8ClampedArray(0);
const EMPTY_TRANSFORMS: readonly MatrixSignalTransform[] = [];
const DEFAULT_MAPPER = createLuminanceMapper();
const UNSET_SOURCE = Symbol("matrix-effect-unset-source");
const NOOP = () => {};
const warnedIssues = new Set<string>();

interface NormalizedGridConfig {
  readonly mode: "auto" | "fixed";
  readonly cellSize: number;
  readonly columns: number | null;
  readonly rows: number | null;
  readonly cellAspectRatio: number;
  readonly maxCells: number;
  readonly signature: string;
}

/** MatrixEffect 内部计算后的网格几何；不会从公共入口导出 */
export interface MatrixResolvedGrid {
  /** 当前列数 */
  readonly columns: number;
  /** 当前行数 */
  readonly rows: number;
  /** 实际单元格 CSS 宽度 */
  readonly cellWidth: number;
  /** 实际单元格 CSS 高度 */
  readonly cellHeight: number;
  /** 本次网格使用的目标单元格宽高比 */
  readonly cellAspectRatio: number;
}

/** MatrixEffect 内部计算后的可见 Canvas backing store；不会从公共入口导出 */
export interface MatrixCanvasMetrics {
  /** 受 maxDpr、像素预算和单轴预算限制后的名义 DPR */
  readonly dpr: number;
  /** backing store 整数宽度 */
  readonly backingWidth: number;
  /** backing store 整数高度 */
  readonly backingHeight: number;
  /** CSS x 坐标到 backing store 的实际缩放 */
  readonly scaleX: number;
  /** CSS y 坐标到 backing store 的实际缩放 */
  readonly scaleY: number;
}

interface MatrixSize {
  cssWidth: number;
  cssHeight: number;
  devicePixelRatio: number;
}

interface CanvasSurface {
  canvas: HTMLCanvasElement;
  ctx: CanvasRenderingContext2D;
}

interface MutableMatrixFrame {
  columns: number;
  rows: number;
  rgba: Uint8ClampedArray;
  values: Float32Array;
  previousValues: Float32Array | null;
}

interface MutableMatrixFrameContext {
  time: number;
  deltaTime: number;
  frame: number;
  cssWidth: number;
  cssHeight: number;
  cellWidth: number;
  cellHeight: number;
  dpr: number;
}

interface MutableProceduralContext {
  ctx: CanvasRenderingContext2D;
  width: number;
  height: number;
  columns: number;
  rows: number;
  time: number;
  deltaTime: number;
  frame: number;
}

function createMutableProceduralContext(): MutableProceduralContext {
  return {
    ctx: null as unknown as CanvasRenderingContext2D,
    width: 0,
    height: 0,
    columns: 0,
    rows: 0,
    time: 0,
    deltaTime: 0,
    frame: 0,
  };
}

interface MatrixFrameBuffers {
  columns: number;
  rows: number;
  values: Float32Array;
  previousValues: Float32Array;
  hasPreviousValues: boolean;
  frame: MutableMatrixFrame;
}

interface MatrixLifecycleCallbacks {
  onStatusChange?: (status: MatrixEffectStatus) => void;
  onReady?: () => void;
  onError?: (error: MatrixEffectError) => void;
}

type MatrixTargetFrameRate = 30 | 60;
type MatrixFrameOutcome = "committed" | "loading" | "idle" | "stale" | "error";

interface MatrixAnimationFrameLease {
  id: number;
}

interface MatrixPlaybackClock {
  effectiveTimeMs: number;
  lastSuccessfulContinuousTimestampMs: number | null;
}

interface MutableMatrixFrameTiming {
  continuous: boolean;
  timestampMs: number;
  timeSeconds: number;
  deltaTimeSeconds: number;
  playbackGeneration: number;
  pipelineStartedAtMs: number;
  committedCostMs: number;
}

/** MatrixEffect 内部 auto FPS 控制器状态；不会从公共入口导出 */
export interface MatrixAdaptiveFrameRateState {
  preferredFrameRate: MatrixTargetFrameRate;
  targetFrameRate: MatrixTargetFrameRate;
  costEmaMs: number | null;
  missEma: number | null;
  lastCostTimestampMs: number | null;
  lastRafTimestampMs: number | null;
  pressureSinceMs: number | null;
  healthySinceMs: number | null;
  lastDowngradeTimestampMs: number | null;
}

interface RendererLease {
  renderer: MatrixRenderer;
  token: object;
}

function isDevelopment() {
  return (
    typeof process !== "undefined" && process.env.NODE_ENV === "development"
  );
}

function warnOnce(issue: string, message: string) {
  if (!isDevelopment() || warnedIssues.has(issue)) {
    return;
  }

  warnedIssues.add(issue);
  console.warn(`[MatrixEffect] ${message}`);
}

function reportLifecycleFailure(name: string, cause: unknown) {
  if (!isDevelopment()) {
    return;
  }

  console.error(`[MatrixEffect] ${name} 回调执行失败。`, cause);
}

function reportRendererDisposeFailure(cause: unknown) {
  if (!isDevelopment()) {
    return;
  }

  console.error("[MatrixEffect] Renderer dispose() 执行失败。", cause);
}

function isThenable(value: unknown): value is PromiseLike<unknown> {
  return (
    (typeof value === "object" || typeof value === "function") &&
    value !== null &&
    typeof (value as PromiseLike<unknown>).then === "function"
  );
}

function consumeThenableRejection(value: PromiseLike<unknown>) {
  try {
    void Promise.resolve(value).catch(NOOP);
  } catch {
    // then getter 异常会由同步管线错误处理；这里只负责避免 rejection 外泄。
  }
}

function createAsyncContractError(
  value: unknown,
  message: string,
): TypeError | null {
  if (!isThenable(value)) {
    return null;
  }

  consumeThenableRejection(value);
  return new TypeError(message);
}

function observeLifecycleResult(name: string, value: unknown) {
  if (!isThenable(value)) {
    return;
  }

  try {
    void Promise.resolve(value).catch((cause) => {
      reportLifecycleFailure(name, cause);
    });
  } catch (cause) {
    reportLifecycleFailure(name, cause);
  }
}

function enqueueMicrotask(callback: () => void) {
  if (typeof queueMicrotask === "function") {
    queueMicrotask(callback);
    return;
  }

  void Promise.resolve().then(callback);
}

function normalizePositiveNumber(
  value: number | undefined,
  fallback: number,
  issue: string,
  message: string,
) {
  if (value === undefined) {
    return fallback;
  }

  if (Number.isFinite(value) && value > 0) {
    return value;
  }

  warnOnce(issue, message);
  return fallback;
}

function normalizeOptionalGridDimension(
  value: number | undefined,
  issue: string,
  message: string,
): number | null {
  if (value === undefined) {
    return null;
  }

  if (!Number.isFinite(value) || value <= 0) {
    warnOnce(issue, message);
    return null;
  }

  return Math.max(1, Math.min(Number.MAX_SAFE_INTEGER, Math.round(value)));
}

function normalizeGridConfigValues(
  mode: MatrixGridConfig["mode"] | undefined,
  cellSize: number | undefined,
  columns: number | undefined,
  rows: number | undefined,
  gridCellAspectRatio: number | undefined,
  maxCells: number | undefined,
  rendererCellAspectRatio: number | undefined,
): NormalizedGridConfig {
  const resolvedMode = mode === "fixed" ? "fixed" : "auto";
  const rendererAspectRatio = normalizePositiveNumber(
    rendererCellAspectRatio,
    DEFAULT_CELL_ASPECT_RATIO,
    "renderer-cell-aspect-ratio",
    "Renderer cellAspectRatio 必须是有限正数；已回退到 1。",
  );
  const cellAspectRatio = normalizePositiveNumber(
    gridCellAspectRatio,
    rendererAspectRatio,
    "grid-cell-aspect-ratio",
    "grid.cellAspectRatio 必须是有限正数；已回退到 Renderer 建议值。",
  );
  const resolvedCellSize = normalizePositiveNumber(
    cellSize,
    DEFAULT_CELL_SIZE,
    "grid-cell-size",
    "grid.cellSize 必须是有限正数；已回退到 10。",
  );
  const resolvedColumns =
    resolvedMode === "fixed"
      ? normalizeOptionalGridDimension(
          columns,
          "grid-columns",
          "fixed grid.columns 必须是有限正数；已回退到 auto 的 10px 推导。",
        )
      : null;
  const resolvedRows =
    resolvedMode === "fixed"
      ? normalizeOptionalGridDimension(
          rows,
          "grid-rows",
          "fixed grid.rows 必须是有限正数；已按未传处理。",
        )
      : null;
  const resolvedMaxCells = Math.max(
    1,
    Math.min(
      Number.MAX_SAFE_INTEGER,
      Math.floor(
        normalizePositiveNumber(
          maxCells,
          DEFAULT_MAX_CELLS,
          "grid-max-cells",
          "grid.maxCells 必须是有限正数；已回退到 10000。",
        ),
      ),
    ),
  );

  if (resolvedMaxCells > LARGE_GRID_WARNING_THRESHOLD) {
    warnOnce(
      "grid-large-max-cells",
      `grid.maxCells=${resolvedMaxCells} 可能造成明显主线程压力。`,
    );
  }

  return {
    mode: resolvedMode,
    cellSize: resolvedCellSize,
    columns: resolvedColumns,
    rows: resolvedRows,
    cellAspectRatio,
    maxCells: resolvedMaxCells,
    signature: [
      resolvedMode,
      resolvedCellSize,
      resolvedColumns ?? "auto",
      resolvedRows ?? "auto",
      cellAspectRatio,
      resolvedMaxCells,
    ].join(":"),
  };
}

function fitsWithinCellLimit(columns: number, rows: number, maxCells: number) {
  return columns <= Math.floor(maxCells / rows);
}

function constrainGridToCellLimit(
  columns: number,
  rows: number,
  maxCells: number,
) {
  if (fitsWithinCellLimit(columns, rows, maxCells)) {
    return { columns, rows };
  }

  const scale = Math.sqrt(maxCells / (columns * rows));
  const scaledColumns = columns * scale;
  const scaledRows = rows * scale;

  if (scaledColumns < 1) {
    return {
      columns: 1,
      rows: Math.max(1, Math.min(rows, maxCells)),
    };
  }

  if (scaledRows < 1) {
    return {
      columns: Math.max(1, Math.min(columns, maxCells)),
      rows: 1,
    };
  }

  let nextColumns = Math.max(1, Math.floor(scaledColumns));
  let nextRows = Math.max(1, Math.floor(scaledRows));

  if (!fitsWithinCellLimit(nextColumns, nextRows, maxCells)) {
    if (nextColumns >= nextRows) {
      nextColumns = Math.max(1, Math.floor(maxCells / nextRows));
    } else {
      nextRows = Math.max(1, Math.floor(maxCells / nextColumns));
    }
  }

  return { columns: nextColumns, rows: nextRows };
}

function resolveNormalizedMatrixGrid(
  cssWidth: number,
  cssHeight: number,
  config: NormalizedGridConfig,
): MatrixResolvedGrid | null {
  if (
    !Number.isFinite(cssWidth) ||
    !Number.isFinite(cssHeight) ||
    cssWidth <= 0 ||
    cssHeight <= 0
  ) {
    return null;
  }

  let columns =
    config.mode === "fixed" && config.columns !== null
      ? config.columns
      : Math.max(1, Math.round(cssWidth / config.cellSize));
  let rows =
    config.mode === "fixed" && config.rows !== null
      ? config.rows
      : Math.max(
          1,
          Math.round((columns * config.cellAspectRatio * cssHeight) / cssWidth),
        );

  ({ columns, rows } = constrainGridToCellLimit(
    columns,
    rows,
    config.maxCells,
  ));

  if (
    columns > MAX_BACKING_STORE_DIMENSION ||
    rows > MAX_BACKING_STORE_DIMENSION
  ) {
    warnOnce(
      "grid-canvas-dimension",
      `网格单轴不能超过 ${MAX_BACKING_STORE_DIMENSION}；已按 Canvas 安全上限收缩。`,
    );
    columns = Math.min(columns, MAX_BACKING_STORE_DIMENSION);
    rows = Math.min(rows, MAX_BACKING_STORE_DIMENSION);
  }

  return {
    columns,
    rows,
    cellWidth: cssWidth / columns,
    cellHeight: cssHeight / rows,
    cellAspectRatio: config.cellAspectRatio,
  };
}

/**
 * 解析 MatrixEffect 的响应式或固定网格
 *
 * 该函数是内部确定性几何入口，不从组件公共 index 导出。
 */
export function resolveMatrixGrid(
  cssWidth: number,
  cssHeight: number,
  grid?: MatrixGridConfig,
  rendererCellAspectRatio?: number,
): MatrixResolvedGrid | null {
  const config = normalizeGridConfigValues(
    grid?.mode,
    grid?.cellSize,
    grid?.columns,
    grid?.rows,
    grid?.cellAspectRatio,
    grid?.maxCells,
    rendererCellAspectRatio,
  );

  return resolveNormalizedMatrixGrid(cssWidth, cssHeight, config);
}

function normalizeMaxDpr(maxDpr: number | undefined) {
  return normalizePositiveNumber(
    maxDpr,
    DEFAULT_MAX_DPR,
    "max-dpr",
    "maxDpr 必须是有限正数；已回退到 2。",
  );
}

/**
 * 解析受 DPR、总像素和单轴尺寸预算保护的 Canvas backing store
 *
 * 该函数不读取 window，可用于 SSR 安全的确定性验证。
 */
export function resolveMatrixCanvasMetrics(
  cssWidth: number,
  cssHeight: number,
  maxDpr: number = DEFAULT_MAX_DPR,
  devicePixelRatio: number = 1,
): MatrixCanvasMetrics | null {
  if (
    !Number.isFinite(cssWidth) ||
    !Number.isFinite(cssHeight) ||
    cssWidth <= 0 ||
    cssHeight <= 0
  ) {
    return null;
  }

  const resolvedMaxDpr = normalizeMaxDpr(maxDpr);
  const resolvedDeviceDpr =
    Number.isFinite(devicePixelRatio) && devicePixelRatio > 0
      ? devicePixelRatio
      : 1;
  const cssPixels = cssWidth * cssHeight;
  const pixelBudgetDpr = Math.sqrt(MAX_BACKING_STORE_PIXELS / cssPixels);
  const widthBudgetDpr = MAX_BACKING_STORE_DIMENSION / cssWidth;
  const heightBudgetDpr = MAX_BACKING_STORE_DIMENSION / cssHeight;
  const dpr = Math.min(
    resolvedDeviceDpr,
    resolvedMaxDpr,
    pixelBudgetDpr,
    widthBudgetDpr,
    heightBudgetDpr,
  );
  let backingWidth = Math.max(1, Math.round(cssWidth * dpr));
  let backingHeight = Math.max(1, Math.round(cssHeight * dpr));

  backingWidth = Math.min(backingWidth, MAX_BACKING_STORE_DIMENSION);
  backingHeight = Math.min(backingHeight, MAX_BACKING_STORE_DIMENSION);

  if (backingWidth > Math.floor(MAX_BACKING_STORE_PIXELS / backingHeight)) {
    const correction = Math.sqrt(
      MAX_BACKING_STORE_PIXELS / (backingWidth * backingHeight),
    );
    backingWidth = Math.max(1, Math.floor(backingWidth * correction));
    backingHeight = Math.max(1, Math.floor(backingHeight * correction));

    if (backingWidth > Math.floor(MAX_BACKING_STORE_PIXELS / backingHeight)) {
      if (backingWidth >= backingHeight) {
        backingWidth = Math.max(
          1,
          Math.floor(MAX_BACKING_STORE_PIXELS / backingHeight),
        );
      } else {
        backingHeight = Math.max(
          1,
          Math.floor(MAX_BACKING_STORE_PIXELS / backingWidth),
        );
      }
    }
  }

  return {
    dpr,
    backingWidth,
    backingHeight,
    scaleX: backingWidth / cssWidth,
    scaleY: backingHeight / cssHeight,
  };
}

/** 把完整 Transform 链的输出原地规范到有限的 0..1 区间 */
export function normalizeMatrixSignalValues(values: Float32Array) {
  for (let index = 0; index < values.length; index += 1) {
    const value = values[index];

    if (!Number.isFinite(value) || value <= 0) {
      values[index] = 0;
    } else if (value >= 1) {
      values[index] = 1;
    }
  }
}

function normalizeMatrixFrameRate(
  frameRate: MatrixFrameRate | undefined,
): MatrixFrameRate {
  if (frameRate === 30 || frameRate === 60 || frameRate === "auto") {
    return frameRate;
  }

  warnOnce(
    "frame-rate",
    'frameRate 必须是 "auto"、30 或 60；已回退到 "auto"。',
  );
  return DEFAULT_FRAME_RATE;
}

function normalizeMatrixReducedMotion(
  reducedMotion: MatrixReducedMotion | undefined,
): MatrixReducedMotion {
  if (reducedMotion === "ignore" || reducedMotion === "freeze") {
    return reducedMotion;
  }

  warnOnce(
    "reduced-motion",
    'reducedMotion 必须是 "freeze" 或 "ignore"；已回退到 "freeze"。',
  );
  return DEFAULT_REDUCED_MOTION;
}

function resolveRendererPreferredFrameRate(
  renderer: MatrixRenderer,
): MatrixTargetFrameRate {
  return renderer.preferredFrameRate === 30 ? 30 : 60;
}

function getMatrixFrameIntervalMs(frameRate: MatrixTargetFrameRate) {
  return 1_000 / frameRate;
}

/** 创建 MatrixEffect 内部 auto FPS 控制器；不会从公共入口导出 */
export function createMatrixAdaptiveFrameRateState(
  preferredFrameRate: MatrixTargetFrameRate = 60,
): MatrixAdaptiveFrameRateState {
  const normalizedPreferredFrameRate = preferredFrameRate === 30 ? 30 : 60;

  return {
    preferredFrameRate: normalizedPreferredFrameRate,
    targetFrameRate: normalizedPreferredFrameRate,
    costEmaMs: null,
    missEma: null,
    lastCostTimestampMs: null,
    lastRafTimestampMs: null,
    pressureSinceMs: null,
    healthySinceMs: null,
    lastDowngradeTimestampMs: null,
  };
}

/** 清空 auto FPS 的负载样本但保留当前目标档位 */
export function clearMatrixAdaptiveFrameRateSamples(
  state: MatrixAdaptiveFrameRateState,
) {
  state.costEmaMs = null;
  state.missEma = null;
  state.lastCostTimestampMs = null;
  state.lastRafTimestampMs = null;
  state.pressureSinceMs = null;
  state.healthySinceMs = null;
}

function updateTimeNormalizedEma(
  previous: number | null,
  sample: number,
  elapsedMs: number,
) {
  if (previous === null) {
    return sample;
  }

  if (!Number.isFinite(elapsedMs) || elapsedMs <= 0) {
    return previous;
  }

  const alpha = -Math.expm1(-elapsedMs / ADAPTIVE_EMA_TIME_CONSTANT_MS);
  return previous + (sample - previous) * alpha;
}

function reconcileMatrixAdaptiveFrameRate(
  state: MatrixAdaptiveFrameRateState,
  timestampMs: number,
) {
  if (state.preferredFrameRate !== 60) {
    state.pressureSinceMs = null;
    state.healthySinceMs = null;
    return false;
  }

  if (state.targetFrameRate === 60) {
    state.healthySinceMs = null;
    const isOverBudget =
      (state.costEmaMs !== null &&
        state.costEmaMs >= ADAPTIVE_DOWNGRADE_COST_MS) ||
      (state.missEma !== null && state.missEma >= ADAPTIVE_DOWNGRADE_MISS_EMA);

    if (!isOverBudget) {
      state.pressureSinceMs = null;
      return false;
    }

    state.pressureSinceMs ??= timestampMs;

    if (timestampMs - state.pressureSinceMs < ADAPTIVE_DOWNGRADE_SUSTAIN_MS) {
      return false;
    }

    state.targetFrameRate = 30;
    state.lastDowngradeTimestampMs = timestampMs;
    state.pressureSinceMs = null;
    state.healthySinceMs = null;
    return true;
  }

  state.pressureSinceMs = null;
  const isHealthy =
    state.costEmaMs !== null &&
    state.missEma !== null &&
    state.costEmaMs <= ADAPTIVE_UPGRADE_COST_MS &&
    state.missEma <= ADAPTIVE_UPGRADE_MISS_EMA;

  if (!isHealthy) {
    state.healthySinceMs = null;
    return false;
  }

  state.healthySinceMs ??= timestampMs;
  const hasStableWindow =
    timestampMs - state.healthySinceMs >= ADAPTIVE_UPGRADE_SUSTAIN_MS;
  const hasCooledDown =
    state.lastDowngradeTimestampMs !== null &&
    timestampMs - state.lastDowngradeTimestampMs >=
      ADAPTIVE_UPGRADE_COOLDOWN_MS;

  if (!hasStableWindow || !hasCooledDown) {
    return false;
  }

  state.targetFrameRate = 60;
  state.pressureSinceMs = null;
  state.healthySinceMs = null;
  return true;
}

/** 记录原始 rAF 间隔，并在需要切换 auto FPS 档位时返回 true */
export function recordMatrixAdaptiveRafSample(
  state: MatrixAdaptiveFrameRateState,
  timestampMs: number,
) {
  if (!Number.isFinite(timestampMs)) {
    return false;
  }

  const previousTimestamp = state.lastRafTimestampMs;
  state.lastRafTimestampMs = timestampMs;

  if (previousTimestamp === null || timestampMs <= previousTimestamp) {
    return reconcileMatrixAdaptiveFrameRate(state, timestampMs);
  }

  const elapsedMs = timestampMs - previousTimestamp;
  const missedSample = elapsedMs >= ADAPTIVE_MISSED_RAF_THRESHOLD_MS ? 1 : 0;
  state.missEma = updateTimeNormalizedEma(
    state.missEma,
    missedSample,
    elapsedMs,
  );
  return reconcileMatrixAdaptiveFrameRate(state, timestampMs);
}

/** 记录成功连续帧的完整管线耗时，并在需要切档时返回 true */
export function recordMatrixAdaptiveCostSample(
  state: MatrixAdaptiveFrameRateState,
  timestampMs: number,
  costMs: number,
) {
  if (!Number.isFinite(timestampMs) || !Number.isFinite(costMs) || costMs < 0) {
    return false;
  }

  const previousTimestamp = state.lastCostTimestampMs;
  state.lastCostTimestampMs = timestampMs;
  state.costEmaMs = updateTimeNormalizedEma(
    state.costEmaMs,
    costMs,
    previousTimestamp === null ? 0 : timestampMs - previousTimestamp,
  );
  return reconcileMatrixAdaptiveFrameRate(state, timestampMs);
}

/** 判断当前 rAF timestamp 是否已到连续绘制 deadline */
export function isMatrixFrameDeadlineDue(
  timestampMs: number,
  nextDeadlineMs: number | null,
) {
  return (
    nextDeadlineMs === null ||
    timestampMs + FRAME_GATE_EPSILON_MS >= nextDeadlineMs
  );
}

/** 把连续帧 deadline 前推到当前 timestamp 之后，且不补画历史帧 */
export function advanceMatrixFrameDeadline(
  timestampMs: number,
  nextDeadlineMs: number | null,
  frameRate: MatrixTargetFrameRate,
) {
  const intervalMs = getMatrixFrameIntervalMs(frameRate);

  if (nextDeadlineMs === null || !Number.isFinite(nextDeadlineMs)) {
    return timestampMs + intervalMs;
  }

  const slots = Math.max(
    1,
    Math.ceil(
      (timestampMs + FRAME_GATE_EPSILON_MS - nextDeadlineMs) / intervalMs,
    ),
  );
  return nextDeadlineMs + slots * intervalMs;
}

/** 计算成功连续帧可提交的播放增量，结果限制在 0..100ms */
export function resolveMatrixPlaybackDeltaMs(
  lastSuccessfulTimestampMs: number | null,
  timestampMs: number,
) {
  if (
    lastSuccessfulTimestampMs === null ||
    !Number.isFinite(lastSuccessfulTimestampMs) ||
    !Number.isFinite(timestampMs) ||
    timestampMs <= lastSuccessfulTimestampMs
  ) {
    return 0;
  }

  return Math.min(
    MAX_PLAYBACK_DELTA_MS,
    timestampMs - lastSuccessfulTimestampMs,
  );
}

function readHighResolutionTime() {
  return typeof performance !== "undefined" &&
    typeof performance.now === "function"
    ? performance.now()
    : Date.now();
}

function createMatrixEffectError(
  code: MatrixEffectError["code"],
  message: string,
  recoverable: boolean,
  cause?: unknown,
): MatrixEffectError {
  return {
    code,
    message,
    recoverable,
    ...(cause === undefined ? {} : { cause }),
  };
}

function createInternalCanvasSurface(
  contextOptions?: CanvasRenderingContext2DSettings,
): CanvasSurface | null {
  if (typeof document === "undefined") {
    return null;
  }

  const canvas = document.createElement("canvas");
  const ctx = canvas.getContext("2d", contextOptions);

  return ctx === null ? null : { canvas, ctx };
}

function resetFrameHistory(buffers: MatrixFrameBuffers | null) {
  if (buffers !== null) {
    buffers.hasPreviousValues = false;
    buffers.frame.previousValues = null;
  }
}

function safelyRestoreContext(ctx: CanvasRenderingContext2D) {
  try {
    ctx.restore();
    return null;
  } catch (cause) {
    return cause;
  }
}

function clearCanvasPixels(
  ctx: CanvasRenderingContext2D,
  canvas: HTMLCanvasElement,
  clearColor: string | null,
) {
  ctx.setTransform(1, 0, 0, 1, 0, 0);
  ctx.globalAlpha = 1;
  ctx.globalCompositeOperation = "source-over";
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.beginPath();

  if (clearColor !== null) {
    ctx.fillStyle = TRANSPARENT_FILL;
    ctx.fillStyle = clearColor;
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  }
}

/**
 * MatrixEffect — 通用视觉矩阵渲染核心
 *
 * 提供可组合的低分辨率采样场管线：
 * - 响应式计算 columns x rows，并限制单元格数与 Canvas backing store
 * - 统一图片、Canvas 和程序化 Source，经 Mapper / Transform 输出信号场
 * - 使用 staging Canvas 事务性提交 Renderer 结果，错误时保留上一成功画面
 * - 使用单一 rAF 链处理动态帧、暂停恢复和合并 invalidate 请求
 * - 根据负载在 30/60 FPS 间自适应，并尊重页面与系统动态偏好
 * - 提供结构化状态、错误、fallback 和 Canvas 无障碍语义
 *
 * @example
 * ```tsx
 * const renderer = {
 *   render(ctx, frame, context) {
 *     ctx.fillStyle = "#18181b";
 *     ctx.fillRect(0, 0, context.cssWidth, context.cssHeight);
 *   },
 * };
 *
 * <MatrixEffect
 *   className="aspect-video w-full"
 *   source={{ type: "image", src: "/example.webp" }}
 *   renderer={renderer}
 * />;
 * ```
 */
export const MatrixEffect = React.forwardRef<
  MatrixEffectHandle,
  MatrixEffectProps
>(function MatrixEffect(
  {
    source,
    renderer,
    mapper = DEFAULT_MAPPER,
    transforms = EMPTY_TRANSFORMS,
    grid,
    playing = true,
    frameRate = DEFAULT_FRAME_RATE,
    maxDpr = DEFAULT_MAX_DPR,
    pauseWhenOffscreen = true,
    reducedMotion = DEFAULT_REDUCED_MOTION,
    clearColor = null,
    canvasClassName,
    decorative = true,
    ariaLabel,
    fallback,
    onStatusChange,
    onReady,
    onError,
    className,
    style,
    ...rootProps
  },
  ref,
) {
  const requestedGridMode = grid?.mode === "fixed" ? "fixed" : "auto";
  const requestedCellSize =
    requestedGridMode === "auto" ? grid?.cellSize : undefined;
  const requestedColumns =
    requestedGridMode === "fixed" ? grid?.columns : undefined;
  const requestedRows = requestedGridMode === "fixed" ? grid?.rows : undefined;
  const requestedGridAspectRatio = grid?.cellAspectRatio;
  const requestedMaxCells = grid?.maxCells;
  const rendererCellAspectRatio = renderer.cellAspectRatio;
  const normalizedGrid = React.useMemo(
    () =>
      normalizeGridConfigValues(
        requestedGridMode,
        requestedCellSize,
        requestedColumns,
        requestedRows,
        requestedGridAspectRatio,
        requestedMaxCells,
        rendererCellAspectRatio,
      ),
    [
      rendererCellAspectRatio,
      requestedCellSize,
      requestedColumns,
      requestedGridAspectRatio,
      requestedGridMode,
      requestedMaxCells,
      requestedRows,
    ],
  );
  const normalizedMaxDpr = normalizeMaxDpr(maxDpr);
  const normalizedFrameRate = normalizeMatrixFrameRate(frameRate);
  const normalizedReducedMotion = normalizeMatrixReducedMotion(reducedMotion);
  const rendererPreferredFrameRate =
    resolveRendererPreferredFrameRate(renderer);

  const rootRef = React.useRef<HTMLDivElement>(null);
  const canvasRef = React.useRef<HTMLCanvasElement>(null);
  const visibleSurfaceRef = React.useRef<CanvasSurface | null>(null);
  const stagingSurfaceRef = React.useRef<CanvasSurface | null>(null);
  const samplingSurfaceRef = React.useRef<CanvasSurface | null>(null);
  const sourceAdapterRef = React.useRef<MatrixSourceAdapter | null>(null);
  const buffersRef = React.useRef<MatrixFrameBuffers | null>(null);
  const sizeRef = React.useRef<MatrixSize>({
    cssWidth: 0,
    cssHeight: 0,
    devicePixelRatio: 1,
  });
  const frameContextRef = React.useRef<MutableMatrixFrameContext>({
    time: 0,
    deltaTime: 0,
    frame: 0,
    cssWidth: 0,
    cssHeight: 0,
    cellWidth: 0,
    cellHeight: 0,
    dpr: 1,
  });
  const proceduralContextRef = React.useRef<MutableProceduralContext>(
    createMutableProceduralContext(),
  );
  const mapperRef = React.useRef<MatrixSignalMapper>(mapper);
  const transformsRef =
    React.useRef<readonly MatrixSignalTransform[]>(transforms);
  const rendererRef = React.useRef<MatrixRenderer>(renderer);
  const gridConfigRef = React.useRef(normalizedGrid);
  const maxDprRef = React.useRef(normalizedMaxDpr);
  const clearColorRef = React.useRef<string | null>(clearColor);
  const rendererVersionRef = React.useRef(0);
  const stagingVersionRef = React.useRef(0);
  const pipelineGenerationRef = React.useRef(0);
  const preparedRendererKeyRef = React.useRef<string | null>(null);
  const activeRendererLeaseRef = React.useRef<RendererLease | null>(null);
  const sourceIdentityRef = React.useRef<MatrixSource | typeof UNSET_SOURCE>(
    UNSET_SOURCE,
  );
  const sourceEpochRef = React.useRef(0);
  const readyEpochRef = React.useRef(-1);
  const successfulFrameRef = React.useRef(0);
  const errorLockRef = React.useRef<MatrixEffectError | null>(null);
  const dirtyRef = React.useRef(true);
  const dirtyGenerationRef = React.useRef(0);
  const lastAttemptedDirtyGenerationRef = React.useRef(-1);
  const playingRef = React.useRef(playing);
  const frameRateRef = React.useRef<MatrixFrameRate>(normalizedFrameRate);
  const pauseWhenOffscreenRef = React.useRef(pauseWhenOffscreen);
  const reducedMotionRef = React.useRef<MatrixReducedMotion>(
    normalizedReducedMotion,
  );
  const preferredFrameRateRef = React.useRef<MatrixTargetFrameRate>(
    rendererPreferredFrameRate,
  );
  const environmentReadyRef = React.useRef(false);
  const environmentLeaseRef = React.useRef<object | null>(null);
  const documentVisibleRef = React.useRef(true);
  const isIntersectingRef = React.useRef(false);
  const prefersReducedMotionRef = React.useRef(false);
  const playbackGenerationRef = React.useRef(0);
  const playbackClockRef = React.useRef<MatrixPlaybackClock>({
    effectiveTimeMs: 0,
    lastSuccessfulContinuousTimestampMs: null,
  });
  const frameTimingRef = React.useRef<MutableMatrixFrameTiming>({
    continuous: false,
    timestampMs: 0,
    timeSeconds: 0,
    deltaTimeSeconds: 0,
    playbackGeneration: 0,
    pipelineStartedAtMs: 0,
    committedCostMs: 0,
  });
  const nextFrameDeadlineRef = React.useRef<number | null>(null);
  const adaptiveFrameRateRef = React.useRef<MatrixAdaptiveFrameRateState>(
    createMatrixAdaptiveFrameRateState(rendererPreferredFrameRate),
  );
  const wasContinuousRef = React.useRef(false);
  const mountedRef = React.useRef(false);
  const frameRequestRef = React.useRef<MatrixAnimationFrameLease | null>(null);
  const frameInProgressRef = React.useRef(false);
  const schedulerTickRef = React.useRef<(timestampMs: number) => void>(
    () => {},
  );
  const reconcileFrameScheduleRef = React.useRef<() => void>(() => {});
  const drawFrameRef = React.useRef<
    (timing: MutableMatrixFrameTiming) => MatrixFrameOutcome
  >(() => "stale");
  const invalidateRef = React.useRef<() => void>(() => {});
  const callbacksRef = React.useRef<MatrixLifecycleCallbacks>({
    onStatusChange,
    onReady,
    onError,
  });
  const statusRef = React.useRef<MatrixEffectStatus>("idle");
  const hasEverSuccessfulFrameRef = React.useRef(false);
  const [status, setStatus] = React.useState<MatrixEffectStatus>("idle");
  const [hasEverSuccessfulFrame, setHasEverSuccessfulFrame] =
    React.useState(false);

  const discardSamplingResources = React.useCallback(() => {
    samplingSurfaceRef.current = null;
    // 旧异步 Source 只能继续持有旧对象，不能在恢复后取得新的采样 ctx。
    proceduralContextRef.current = createMutableProceduralContext();
  }, []);

  const cancelScheduledFrame = React.useCallback(() => {
    const lease = frameRequestRef.current;
    frameRequestRef.current = null;

    if (
      lease !== null &&
      lease.id >= 0 &&
      typeof window !== "undefined" &&
      typeof window.cancelAnimationFrame === "function"
    ) {
      window.cancelAnimationFrame(lease.id);
    }
  }, []);

  const clearContinuousTiming = React.useCallback(() => {
    playbackClockRef.current.lastSuccessfulContinuousTimestampMs = null;
    nextFrameDeadlineRef.current = null;
    clearMatrixAdaptiveFrameRateSamples(adaptiveFrameRateRef.current);
  }, []);

  const resetPlaybackClock = React.useCallback(() => {
    playbackClockRef.current.effectiveTimeMs = 0;
    clearContinuousTiming();
  }, [clearContinuousTiming]);

  const resetAdaptiveFrameRate = React.useCallback(() => {
    const adaptiveFrameRate = createMatrixAdaptiveFrameRateState(
      preferredFrameRateRef.current,
    );
    adaptiveFrameRateRef.current = adaptiveFrameRate;
    const latestCommittedTimestamp =
      playbackClockRef.current.lastSuccessfulContinuousTimestampMs;
    const targetFrameRate =
      frameRateRef.current === "auto"
        ? adaptiveFrameRate.targetFrameRate
        : frameRateRef.current;
    nextFrameDeadlineRef.current =
      latestCommittedTimestamp === null
        ? null
        : latestCommittedTimestamp + getMatrixFrameIntervalMs(targetFrameRate);
  }, []);

  const canDrawNow = React.useCallback(() => {
    const { cssWidth, cssHeight } = sizeRef.current;

    return (
      mountedRef.current &&
      environmentReadyRef.current &&
      documentVisibleRef.current &&
      (!pauseWhenOffscreenRef.current || isIntersectingRef.current) &&
      errorLockRef.current === null &&
      sourceAdapterRef.current !== null &&
      cssWidth > 0 &&
      cssHeight > 0
    );
  }, []);

  const shouldRunContinuously = React.useCallback(() => {
    const sourceAdapter = sourceAdapterRef.current;
    const freezesForReducedMotion =
      reducedMotionRef.current === "freeze" && prefersReducedMotionRef.current;

    return (
      sourceAdapter !== null &&
      sourceAdapter.animated &&
      playingRef.current &&
      !freezesForReducedMotion
    );
  }, []);

  const hasUnattemptedDirtyFrame = React.useCallback(() => {
    return (
      dirtyRef.current &&
      lastAttemptedDirtyGenerationRef.current !== dirtyGenerationRef.current
    );
  }, []);

  const reconcileFrameSchedule = React.useCallback(() => {
    const drawable = canDrawNow();
    const continuous = drawable && shouldRunContinuously();

    if (wasContinuousRef.current !== continuous) {
      wasContinuousRef.current = continuous;
      clearContinuousTiming();
    }

    const shouldSchedule =
      drawable && (continuous || hasUnattemptedDirtyFrame());

    if (!shouldSchedule) {
      cancelScheduledFrame();
      return;
    }

    if (
      frameInProgressRef.current ||
      frameRequestRef.current !== null ||
      typeof window === "undefined" ||
      typeof window.requestAnimationFrame !== "function"
    ) {
      return;
    }

    const lease: MatrixAnimationFrameLease = { id: -1 };
    frameRequestRef.current = lease;

    try {
      lease.id = window.requestAnimationFrame((timestampMs) => {
        if (frameRequestRef.current !== lease) {
          return;
        }

        frameRequestRef.current = null;
        frameInProgressRef.current = true;

        try {
          schedulerTickRef.current(timestampMs);
        } finally {
          frameInProgressRef.current = false;
          reconcileFrameScheduleRef.current();
        }
      });
    } catch {
      if (frameRequestRef.current === lease) {
        frameRequestRef.current = null;
      }
    }
  }, [
    canDrawNow,
    cancelScheduledFrame,
    clearContinuousTiming,
    hasUnattemptedDirtyFrame,
    shouldRunContinuously,
  ]);

  const handlePlaybackGateChange = React.useCallback(() => {
    playbackGenerationRef.current += 1;

    if (dirtyRef.current) {
      // 旧尝试可能因门控变化被放弃，恢复时允许同一需求重新尝试一次。
      dirtyGenerationRef.current += 1;
    }

    clearContinuousTiming();
    cancelScheduledFrame();
    reconcileFrameScheduleRef.current();
  }, [cancelScheduledFrame, clearContinuousTiming]);

  const updateStatus = React.useCallback((nextStatus: MatrixEffectStatus) => {
    if (statusRef.current === nextStatus) {
      return;
    }

    statusRef.current = nextStatus;
    setStatus(nextStatus);

    try {
      const returnedValue: unknown =
        callbacksRef.current.onStatusChange?.(nextStatus);
      observeLifecycleResult("onStatusChange", returnedValue);
    } catch (cause) {
      reportLifecycleFailure("onStatusChange", cause);
    }
  }, []);

  const getVisibleSurface = React.useCallback(() => {
    const canvas = canvasRef.current;

    if (canvas === null) {
      return null;
    }

    const current = visibleSurfaceRef.current;

    if (current?.canvas === canvas) {
      return current;
    }

    const ctx = canvas.getContext("2d");

    if (ctx === null) {
      return null;
    }

    const surface = { canvas, ctx };
    visibleSurfaceRef.current = surface;
    return surface;
  }, []);

  const commitBlankVisibleFrame = React.useCallback(() => {
    if (hasEverSuccessfulFrameRef.current) {
      return;
    }

    const { cssWidth, cssHeight } = sizeRef.current;
    const metrics = resolveMatrixCanvasMetrics(
      cssWidth,
      cssHeight,
      maxDprRef.current,
      typeof window === "undefined" ? 1 : window.devicePixelRatio,
    );

    if (metrics === null) {
      return;
    }

    try {
      const surface = getVisibleSurface();

      if (surface === null) {
        return;
      }

      if (surface.canvas.width !== metrics.backingWidth) {
        surface.canvas.width = metrics.backingWidth;
      }

      if (surface.canvas.height !== metrics.backingHeight) {
        surface.canvas.height = metrics.backingHeight;
      }

      surface.ctx.save();
      clearCanvasPixels(surface.ctx, surface.canvas, clearColorRef.current);
      surface.ctx.restore();
    } catch {
      // 错误兜底绘制属于 best effort，不能递归进入错误上报。
    }
  }, [getVisibleSurface]);

  const handlePipelineError = React.useCallback(
    (error: MatrixEffectError) => {
      if (errorLockRef.current !== null) {
        return;
      }

      errorLockRef.current = error;
      dirtyRef.current = true;
      playbackGenerationRef.current += 1;
      wasContinuousRef.current = false;
      clearContinuousTiming();
      cancelScheduledFrame();
      commitBlankVisibleFrame();
      updateStatus("error");

      try {
        const returnedValue: unknown = callbacksRef.current.onError?.(error);
        observeLifecycleResult("onError", returnedValue);
      } catch (cause) {
        reportLifecycleFailure("onError", cause);
      }
    },
    [
      cancelScheduledFrame,
      clearContinuousTiming,
      commitBlankVisibleFrame,
      updateStatus,
    ],
  );

  const markDirty = React.useCallback(() => {
    dirtyRef.current = true;
    dirtyGenerationRef.current += 1;
    reconcileFrameScheduleRef.current();
  }, []);

  const clearRecoverableError = React.useCallback(() => {
    const error = errorLockRef.current;

    if (error !== null && !error.recoverable) {
      return false;
    }

    errorLockRef.current = null;

    if (error !== null) {
      clearContinuousTiming();
    }

    if (statusRef.current === "error") {
      updateStatus("idle");
    }

    return true;
  }, [clearContinuousTiming, updateStatus]);

  const retryPipeline = React.useCallback(
    (options?: { resetHistory?: boolean; resetRenderer?: boolean }) => {
      pipelineGenerationRef.current += 1;

      if (options?.resetHistory) {
        resetFrameHistory(buffersRef.current);
      }

      if (options?.resetRenderer) {
        preparedRendererKeyRef.current = null;
      }

      clearMatrixAdaptiveFrameRateSamples(adaptiveFrameRateRef.current);
      clearRecoverableError();
      markDirty();
    },
    [clearRecoverableError, markDirty],
  );

  const performFrame = React.useCallback(
    (timing: MutableMatrixFrameTiming): MatrixFrameOutcome => {
      if (
        !mountedRef.current ||
        errorLockRef.current !== null ||
        playbackGenerationRef.current !== timing.playbackGeneration
      ) {
        return "stale";
      }

      const frameDirtyGeneration = dirtyGenerationRef.current;
      const framePipelineGeneration = pipelineGenerationRef.current;
      const framePlaybackGeneration = timing.playbackGeneration;

      const { cssWidth, cssHeight } = sizeRef.current;

      if (cssWidth <= 0 || cssHeight <= 0) {
        updateStatus("idle");
        return "idle";
      }

      const sourceAdapter = sourceAdapterRef.current;

      if (sourceAdapter === null) {
        updateStatus("idle");
        return "idle";
      }

      const isPipelineStale = () =>
        pipelineGenerationRef.current !== framePipelineGeneration ||
        sourceAdapterRef.current !== sourceAdapter;

      const resolvedGrid = resolveNormalizedMatrixGrid(
        cssWidth,
        cssHeight,
        gridConfigRef.current,
      );
      const canvasMetrics = resolveMatrixCanvasMetrics(
        cssWidth,
        cssHeight,
        maxDprRef.current,
        typeof window === "undefined" ? 1 : window.devicePixelRatio,
      );

      if (resolvedGrid === null || canvasMetrics === null) {
        updateStatus("idle");
        return "idle";
      }

      let samplingSurface = samplingSurfaceRef.current;

      try {
        if (samplingSurface === null) {
          samplingSurface = createInternalCanvasSurface({
            willReadFrequently: true,
          });

          if (samplingSurface === null) {
            handlePipelineError(
              createMatrixEffectError(
                "CANVAS_CONTEXT_UNAVAILABLE",
                "MatrixEffect 无法创建采样 Canvas 2D context。",
                false,
              ),
            );
            return "error";
          }

          samplingSurfaceRef.current = samplingSurface;
        }

        if (samplingSurface.canvas.width !== resolvedGrid.columns) {
          samplingSurface.canvas.width = resolvedGrid.columns;
        }

        if (samplingSurface.canvas.height !== resolvedGrid.rows) {
          samplingSurface.canvas.height = resolvedGrid.rows;
        }
      } catch (cause) {
        discardSamplingResources();
        handlePipelineError(
          createMatrixEffectError(
            "CANVAS_CONTEXT_UNAVAILABLE",
            "MatrixEffect 初始化采样 Canvas 失败。",
            true,
            cause,
          ),
        );
        return "error";
      }

      let buffers = buffersRef.current;

      if (
        buffers === null ||
        buffers.columns !== resolvedGrid.columns ||
        buffers.rows !== resolvedGrid.rows
      ) {
        try {
          const cellCount = resolvedGrid.columns * resolvedGrid.rows;
          const values = new Float32Array(cellCount);
          const previousValues = new Float32Array(cellCount);
          const frame: MutableMatrixFrame = {
            columns: resolvedGrid.columns,
            rows: resolvedGrid.rows,
            rgba: EMPTY_RGBA,
            values,
            previousValues: null,
          };
          buffers = {
            columns: resolvedGrid.columns,
            rows: resolvedGrid.rows,
            values,
            previousValues,
            hasPreviousValues: false,
            frame,
          };
          buffersRef.current = buffers;
          preparedRendererKeyRef.current = null;
        } catch (cause) {
          handlePipelineError(
            createMatrixEffectError(
              "CANVAS_CONTEXT_UNAVAILABLE",
              "MatrixEffect 无法为当前网格分配信号缓冲。",
              true,
              cause,
            ),
          );
          return "error";
        }
      }

      const proceduralContext = proceduralContextRef.current;
      proceduralContext.ctx = samplingSurface.ctx;
      proceduralContext.width = resolvedGrid.columns;
      proceduralContext.height = resolvedGrid.rows;
      proceduralContext.columns = resolvedGrid.columns;
      proceduralContext.rows = resolvedGrid.rows;
      proceduralContext.time = timing.timeSeconds;
      proceduralContext.deltaTime = timing.deltaTimeSeconds;
      proceduralContext.frame = successfulFrameRef.current;

      let sourceResult: ReturnType<MatrixSourceAdapter["draw"]>;
      timing.pipelineStartedAtMs = readHighResolutionTime();

      try {
        sourceResult = sourceAdapter.draw(proceduralContext);
      } catch (cause) {
        if (isPipelineStale()) {
          return "stale";
        }

        discardSamplingResources();
        handlePipelineError(
          createMatrixEffectError(
            "SOURCE_RUNTIME_ERROR",
            "MatrixEffect Source adapter 绘制失败。",
            true,
            cause,
          ),
        );
        return "error";
      }

      if (isPipelineStale()) {
        return "stale";
      }

      if (sourceResult.status === "loading") {
        updateStatus("loading");
        return "loading";
      }

      if (sourceResult.status === "idle") {
        updateStatus("idle");
        return "idle";
      }

      if (sourceResult.status === "error") {
        if (sourceResult.error.code === "SOURCE_RUNTIME_ERROR") {
          discardSamplingResources();
        }

        handlePipelineError(sourceResult.error);
        return "error";
      }

      let rgba: Uint8ClampedArray;

      try {
        rgba = samplingSurface.ctx.getImageData(
          0,
          0,
          resolvedGrid.columns,
          resolvedGrid.rows,
        ).data;
      } catch (cause) {
        const error = createMatrixSourceSampleError(cause);

        if (error.code === "SOURCE_SECURITY_ERROR") {
          discardSamplingResources();
        }

        handlePipelineError(error);
        return "error";
      }

      const frame = buffers.frame;
      const frameContext = frameContextRef.current;
      frame.rgba = rgba;
      frame.previousValues = buffers.hasPreviousValues
        ? buffers.previousValues
        : null;
      buffers.values.fill(0);
      frameContext.time = timing.timeSeconds;
      frameContext.deltaTime = timing.deltaTimeSeconds;
      frameContext.frame = successfulFrameRef.current;
      frameContext.cssWidth = cssWidth;
      frameContext.cssHeight = cssHeight;
      frameContext.cellWidth = resolvedGrid.cellWidth;
      frameContext.cellHeight = resolvedGrid.cellHeight;
      frameContext.dpr = canvasMetrics.dpr;

      try {
        const returnedValue: unknown = mapperRef.current(
          frame as MatrixFrame,
          frameContext as MatrixFrameContext,
        );
        const asyncError = createAsyncContractError(
          returnedValue,
          "MatrixEffect Signal Mapper 必须同步完成，不能返回 Promise。",
        );

        if (asyncError !== null) {
          // 异步回调仍可能持有旧 frame；丢弃缓冲以隔离迟到写入。
          buffersRef.current = null;
          throw asyncError;
        }
      } catch (cause) {
        if (isPipelineStale()) {
          return "stale";
        }

        handlePipelineError(
          createMatrixEffectError(
            "MAPPER_RUNTIME_ERROR",
            "MatrixEffect Signal Mapper 执行失败。",
            true,
            cause,
          ),
        );
        return "error";
      }

      if (isPipelineStale()) {
        return "stale";
      }

      const currentTransforms = transformsRef.current;

      for (let index = 0; index < currentTransforms.length; index += 1) {
        try {
          const returnedValue: unknown = currentTransforms[index](
            frame as MatrixFrame,
            frameContext as MatrixFrameContext,
          );
          const asyncError = createAsyncContractError(
            returnedValue,
            `MatrixEffect Transform[${index}] 必须同步完成，不能返回 Promise。`,
          );

          if (asyncError !== null) {
            buffersRef.current = null;
            throw asyncError;
          }
        } catch (cause) {
          if (isPipelineStale()) {
            return "stale";
          }

          handlePipelineError(
            createMatrixEffectError(
              "TRANSFORM_RUNTIME_ERROR",
              `MatrixEffect Transform[${index}] 执行失败。`,
              true,
              cause,
            ),
          );
          return "error";
        }

        if (isPipelineStale()) {
          return "stale";
        }
      }

      normalizeMatrixSignalValues(buffers.values);

      let visibleSurface: CanvasSurface | null;

      try {
        visibleSurface = getVisibleSurface();
      } catch (cause) {
        handlePipelineError(
          createMatrixEffectError(
            "CANVAS_CONTEXT_UNAVAILABLE",
            "MatrixEffect 获取可见 Canvas 2D context 失败。",
            false,
            cause,
          ),
        );
        return "error";
      }

      if (visibleSurface === null) {
        handlePipelineError(
          createMatrixEffectError(
            "CANVAS_CONTEXT_UNAVAILABLE",
            "MatrixEffect 无法获取可见 Canvas 2D context。",
            false,
          ),
        );
        return "error";
      }

      let stagingSurface = stagingSurfaceRef.current;

      try {
        if (stagingSurface === null) {
          stagingSurface = createInternalCanvasSurface();

          if (stagingSurface === null) {
            handlePipelineError(
              createMatrixEffectError(
                "CANVAS_CONTEXT_UNAVAILABLE",
                "MatrixEffect 无法创建 staging Canvas 2D context。",
                false,
              ),
            );
            return "error";
          }

          stagingSurfaceRef.current = stagingSurface;
          stagingVersionRef.current += 1;
          preparedRendererKeyRef.current = null;
        }

        if (stagingSurface.canvas.width !== canvasMetrics.backingWidth) {
          stagingSurface.canvas.width = canvasMetrics.backingWidth;
        }

        if (stagingSurface.canvas.height !== canvasMetrics.backingHeight) {
          stagingSurface.canvas.height = canvasMetrics.backingHeight;
        }
      } catch (cause) {
        handlePipelineError(
          createMatrixEffectError(
            "CANVAS_CONTEXT_UNAVAILABLE",
            "MatrixEffect 初始化 staging Canvas 失败。",
            true,
            cause,
          ),
        );
        return "error";
      }

      const rendererPrepareKey = [
        rendererVersionRef.current,
        stagingVersionRef.current,
        canvasMetrics.backingWidth,
        canvasMetrics.backingHeight,
        cssWidth,
        cssHeight,
        resolvedGrid.columns,
        resolvedGrid.rows,
        resolvedGrid.cellWidth,
        resolvedGrid.cellHeight,
        canvasMetrics.dpr,
      ].join(":");
      const currentRenderer = rendererRef.current;
      const needsPrepare =
        preparedRendererKeyRef.current !== rendererPrepareKey;
      let rendererPhase = needsPrepare ? "prepare" : "render";
      let stagingContextSaved = false;

      try {
        stagingSurface.ctx.save();
        stagingContextSaved = true;
        clearCanvasPixels(
          stagingSurface.ctx,
          stagingSurface.canvas,
          clearColorRef.current,
        );
        stagingSurface.ctx.setTransform(
          canvasMetrics.scaleX,
          0,
          0,
          canvasMetrics.scaleY,
          0,
          0,
        );
        stagingSurface.ctx.beginPath();

        if (needsPrepare) {
          const returnedValue: unknown = currentRenderer.prepare?.(
            stagingSurface.ctx,
            frame as MatrixFrame,
            frameContext as MatrixFrameContext,
          );
          const asyncError = createAsyncContractError(
            returnedValue,
            "MatrixEffect Renderer prepare() 必须同步完成，不能返回 Promise。",
          );

          if (asyncError !== null) {
            buffersRef.current = null;
            throw asyncError;
          }

          preparedRendererKeyRef.current = rendererPrepareKey;
        }

        rendererPhase = "render";
        const returnedValue: unknown = currentRenderer.render(
          stagingSurface.ctx,
          frame as MatrixFrame,
          frameContext as MatrixFrameContext,
        );
        const asyncError = createAsyncContractError(
          returnedValue,
          "MatrixEffect Renderer render() 必须同步完成，不能返回 Promise。",
        );

        if (asyncError !== null) {
          buffersRef.current = null;
          throw asyncError;
        }

        stagingSurface.ctx.beginPath();
      } catch (cause) {
        if (stagingContextSaved) {
          try {
            stagingSurface.ctx.beginPath();
          } catch {
            // 后续 restore 仍需执行。
          }

          safelyRestoreContext(stagingSurface.ctx);
        }

        // Renderer 可能留下未配平状态或异步持有 ctx，错误后不再复用该 surface。
        stagingSurfaceRef.current = null;
        preparedRendererKeyRef.current = null;

        if (isPipelineStale()) {
          return "stale";
        }

        handlePipelineError(
          createMatrixEffectError(
            "RENDERER_RUNTIME_ERROR",
            `MatrixEffect Renderer ${rendererPhase}() 执行失败。`,
            true,
            cause,
          ),
        );
        return "error";
      }

      const stagingRestoreError = safelyRestoreContext(stagingSurface.ctx);

      if (stagingRestoreError !== null) {
        stagingSurfaceRef.current = null;
        preparedRendererKeyRef.current = null;

        if (isPipelineStale()) {
          return "stale";
        }

        handlePipelineError(
          createMatrixEffectError(
            "RENDERER_RUNTIME_ERROR",
            "MatrixEffect Renderer 未能恢复 staging Canvas 状态。",
            true,
            stagingRestoreError,
          ),
        );
        return "error";
      }

      if (
        pipelineGenerationRef.current !== framePipelineGeneration ||
        playbackGenerationRef.current !== framePlaybackGeneration ||
        sourceAdapterRef.current !== sourceAdapter
      ) {
        return "stale";
      }

      let visibleContextSaved = false;

      try {
        if (visibleSurface.canvas.width !== canvasMetrics.backingWidth) {
          visibleSurface.canvas.width = canvasMetrics.backingWidth;
        }

        if (visibleSurface.canvas.height !== canvasMetrics.backingHeight) {
          visibleSurface.canvas.height = canvasMetrics.backingHeight;
        }

        visibleSurface.ctx.save();
        visibleContextSaved = true;
        visibleSurface.ctx.setTransform(1, 0, 0, 1, 0, 0);
        visibleSurface.ctx.globalAlpha = 1;
        visibleSurface.ctx.globalCompositeOperation = "copy";
        visibleSurface.ctx.imageSmoothingEnabled = false;
        visibleSurface.ctx.drawImage(stagingSurface.canvas, 0, 0);
        visibleSurface.ctx.beginPath();
      } catch (cause) {
        if (visibleContextSaved) {
          safelyRestoreContext(visibleSurface.ctx);
        }

        handlePipelineError(
          createMatrixEffectError(
            "CANVAS_CONTEXT_UNAVAILABLE",
            "MatrixEffect 提交 staging Canvas 到可见 Canvas 失败。",
            false,
            cause,
          ),
        );
        return "error";
      }

      const visibleRestoreError = safelyRestoreContext(visibleSurface.ctx);

      if (visibleRestoreError !== null) {
        handlePipelineError(
          createMatrixEffectError(
            "CANVAS_CONTEXT_UNAVAILABLE",
            "MatrixEffect 未能恢复可见 Canvas 状态。",
            false,
            visibleRestoreError,
          ),
        );
        return "error";
      }

      if (
        pipelineGenerationRef.current !== framePipelineGeneration ||
        playbackGenerationRef.current !== framePlaybackGeneration ||
        sourceAdapterRef.current !== sourceAdapter
      ) {
        return "stale";
      }

      timing.committedCostMs = Math.max(
        0,
        readHighResolutionTime() - timing.pipelineStartedAtMs,
      );

      if (timing.continuous) {
        const clock = playbackClockRef.current;
        clock.effectiveTimeMs = timing.timeSeconds * 1_000;
        clock.lastSuccessfulContinuousTimestampMs = timing.timestampMs;
      }

      buffers.previousValues.set(buffers.values);
      buffers.hasPreviousValues = true;
      successfulFrameRef.current += 1;
      dirtyRef.current = dirtyGenerationRef.current !== frameDirtyGeneration;

      if (!hasEverSuccessfulFrameRef.current) {
        hasEverSuccessfulFrameRef.current = true;
        setHasEverSuccessfulFrame(true);
      }

      updateStatus("ready");

      if (
        pipelineGenerationRef.current !== framePipelineGeneration ||
        sourceAdapterRef.current !== sourceAdapter
      ) {
        return "committed";
      }

      if (readyEpochRef.current !== sourceEpochRef.current) {
        readyEpochRef.current = sourceEpochRef.current;

        try {
          const returnedValue: unknown = callbacksRef.current.onReady?.();
          observeLifecycleResult("onReady", returnedValue);
        } catch (cause) {
          reportLifecycleFailure("onReady", cause);
        }
      }

      return "committed";
    },
    [
      discardSamplingResources,
      getVisibleSurface,
      handlePipelineError,
      updateStatus,
    ],
  );

  const schedulerTick = React.useCallback(
    (timestampMs: number) => {
      if (!canDrawNow()) {
        return;
      }

      const continuous = shouldRunContinuously();
      const adaptiveFrameRate = adaptiveFrameRateRef.current;

      if (!continuous && !hasUnattemptedDirtyFrame()) {
        return;
      }

      if (
        continuous &&
        frameRateRef.current === "auto" &&
        recordMatrixAdaptiveRafSample(adaptiveFrameRate, timestampMs)
      ) {
        const latestCommittedTimestamp =
          playbackClockRef.current.lastSuccessfulContinuousTimestampMs;
        nextFrameDeadlineRef.current =
          (latestCommittedTimestamp ?? timestampMs) +
          getMatrixFrameIntervalMs(adaptiveFrameRate.targetFrameRate);
      }

      const targetFrameRate =
        frameRateRef.current === "auto"
          ? adaptiveFrameRate.targetFrameRate
          : frameRateRef.current;

      if (
        continuous &&
        !isMatrixFrameDeadlineDue(timestampMs, nextFrameDeadlineRef.current)
      ) {
        return;
      }

      if (continuous) {
        nextFrameDeadlineRef.current = advanceMatrixFrameDeadline(
          timestampMs,
          nextFrameDeadlineRef.current,
          targetFrameRate,
        );
      }

      if (dirtyRef.current) {
        lastAttemptedDirtyGenerationRef.current = dirtyGenerationRef.current;
      }

      const clock = playbackClockRef.current;
      const deltaMs = continuous
        ? resolveMatrixPlaybackDeltaMs(
            clock.lastSuccessfulContinuousTimestampMs,
            timestampMs,
          )
        : 0;
      const timing = frameTimingRef.current;
      timing.continuous = continuous;
      timing.timestampMs = timestampMs;
      timing.timeSeconds = (clock.effectiveTimeMs + deltaMs) / 1_000;
      timing.deltaTimeSeconds = deltaMs / 1_000;
      timing.playbackGeneration = playbackGenerationRef.current;
      timing.pipelineStartedAtMs = 0;
      timing.committedCostMs = 0;

      const framePipelineGeneration = pipelineGenerationRef.current;
      const outcome = drawFrameRef.current(timing);

      if (
        outcome === "committed" &&
        continuous &&
        frameRateRef.current === "auto" &&
        adaptiveFrameRateRef.current === adaptiveFrameRate &&
        pipelineGenerationRef.current === framePipelineGeneration &&
        playbackGenerationRef.current === timing.playbackGeneration &&
        recordMatrixAdaptiveCostSample(
          adaptiveFrameRate,
          timestampMs,
          timing.committedCostMs,
        )
      ) {
        nextFrameDeadlineRef.current =
          timestampMs +
          getMatrixFrameIntervalMs(adaptiveFrameRate.targetFrameRate);
      }
    },
    [canDrawNow, hasUnattemptedDirtyFrame, shouldRunContinuously],
  );

  React.useLayoutEffect(() => {
    callbacksRef.current = { onStatusChange, onReady, onError };
  }, [onError, onReady, onStatusChange]);

  React.useLayoutEffect(() => {
    drawFrameRef.current = performFrame;
    schedulerTickRef.current = schedulerTick;
    reconcileFrameScheduleRef.current = reconcileFrameSchedule;
    invalidateRef.current = markDirty;
  }, [markDirty, performFrame, reconcileFrameSchedule, schedulerTick]);

  React.useLayoutEffect(() => {
    const environmentLease = {};
    const root = rootRef.current;
    let intersectionObserver: IntersectionObserver | null = null;
    let mediaQuery: MediaQueryList | null = null;
    let mediaQueryListenerMode: "event" | "legacy" | null = null;

    environmentLeaseRef.current = environmentLease;
    mountedRef.current = true;
    documentVisibleRef.current = document.visibilityState === "visible";
    isIntersectingRef.current = false;
    prefersReducedMotionRef.current = false;

    const isCurrentEnvironment = () =>
      environmentLeaseRef.current === environmentLease && mountedRef.current;

    const applyObservedValue = (
      target: React.MutableRefObject<boolean>,
      value: boolean,
      affectsPlayback: () => boolean,
    ) => {
      if (!isCurrentEnvironment() || target.current === value) {
        return;
      }

      target.current = value;

      if (affectsPlayback()) {
        handlePlaybackGateChange();
      }
    };

    const handleVisibilityChange = () => {
      applyObservedValue(
        documentVisibleRef,
        document.visibilityState === "visible",
        () => true,
      );
    };

    const handleReducedMotionChange = (event: MediaQueryListEvent) => {
      applyObservedValue(
        prefersReducedMotionRef,
        event.matches,
        () => reducedMotionRef.current === "freeze",
      );
    };

    document.addEventListener("visibilitychange", handleVisibilityChange);

    if (typeof window.matchMedia === "function") {
      try {
        mediaQuery = window.matchMedia("(prefers-reduced-motion: reduce)");
        prefersReducedMotionRef.current = mediaQuery.matches;

        if (typeof mediaQuery.addEventListener === "function") {
          mediaQuery.addEventListener("change", handleReducedMotionChange);
          mediaQueryListenerMode = "event";
        } else if (typeof mediaQuery.addListener === "function") {
          mediaQuery.addListener(handleReducedMotionChange);
          mediaQueryListenerMode = "legacy";
        }
      } catch {
        mediaQuery = null;
        mediaQueryListenerMode = null;
        prefersReducedMotionRef.current = false;
      }
    }

    if (root === null || typeof IntersectionObserver === "undefined") {
      isIntersectingRef.current = true;
    } else {
      try {
        intersectionObserver = new IntersectionObserver(
          (entries) => {
            if (!isCurrentEnvironment()) {
              return;
            }

            const entry = entries.find((item) => item.target === root);

            if (entry !== undefined) {
              applyObservedValue(
                isIntersectingRef,
                entry.isIntersecting || entry.intersectionRatio > 0,
                () => pauseWhenOffscreenRef.current,
              );
            }
          },
          { rootMargin: OFFSCREEN_ROOT_MARGIN, threshold: 0 },
        );
        intersectionObserver.observe(root);
      } catch {
        intersectionObserver?.disconnect();
        intersectionObserver = null;
        isIntersectingRef.current = true;
      }
    }

    environmentReadyRef.current = true;
    reconcileFrameScheduleRef.current();

    return () => {
      if (environmentLeaseRef.current === environmentLease) {
        environmentLeaseRef.current = null;
      }

      environmentReadyRef.current = false;
      mountedRef.current = false;
      playbackGenerationRef.current += 1;
      pipelineGenerationRef.current += 1;
      wasContinuousRef.current = false;
      clearContinuousTiming();
      cancelScheduledFrame();
      document.removeEventListener("visibilitychange", handleVisibilityChange);
      intersectionObserver?.disconnect();

      if (mediaQueryListenerMode === "event") {
        mediaQuery?.removeEventListener("change", handleReducedMotionChange);
      } else if (mediaQueryListenerMode === "legacy") {
        mediaQuery?.removeListener(handleReducedMotionChange);
      }

      visibleSurfaceRef.current = null;
      stagingSurfaceRef.current = null;
      discardSamplingResources();
      buffersRef.current = null;
    };
  }, [
    cancelScheduledFrame,
    clearContinuousTiming,
    discardSamplingResources,
    handlePlaybackGateChange,
  ]);

  const handleRef = React.useRef<MatrixEffectHandle | null>(null);

  if (handleRef.current === null) {
    handleRef.current = {
      get canvas() {
        return canvasRef.current;
      },
      invalidate() {
        invalidateRef.current();
      },
    };
  }

  React.useImperativeHandle(
    ref,
    () => handleRef.current as MatrixEffectHandle,
    [],
  );

  React.useLayoutEffect(() => {
    if (playingRef.current === playing) {
      return;
    }

    playingRef.current = playing;
    handlePlaybackGateChange();
  }, [handlePlaybackGateChange, playing]);

  React.useLayoutEffect(() => {
    const didFrameRateChange = frameRateRef.current !== normalizedFrameRate;
    const didPreferredFrameRateChange =
      preferredFrameRateRef.current !== rendererPreferredFrameRate;

    if (!didFrameRateChange && !didPreferredFrameRateChange) {
      return;
    }

    frameRateRef.current = normalizedFrameRate;
    preferredFrameRateRef.current = rendererPreferredFrameRate;
    resetAdaptiveFrameRate();
    cancelScheduledFrame();
    reconcileFrameScheduleRef.current();
  }, [
    cancelScheduledFrame,
    normalizedFrameRate,
    rendererPreferredFrameRate,
    resetAdaptiveFrameRate,
  ]);

  React.useLayoutEffect(() => {
    if (pauseWhenOffscreenRef.current === pauseWhenOffscreen) {
      return;
    }

    pauseWhenOffscreenRef.current = pauseWhenOffscreen;
    handlePlaybackGateChange();
  }, [handlePlaybackGateChange, pauseWhenOffscreen]);

  React.useLayoutEffect(() => {
    if (reducedMotionRef.current === normalizedReducedMotion) {
      return;
    }

    reducedMotionRef.current = normalizedReducedMotion;
    handlePlaybackGateChange();
  }, [handlePlaybackGateChange, normalizedReducedMotion]);

  React.useLayoutEffect(() => {
    const previousRenderer = rendererRef.current;
    const didChange = previousRenderer !== renderer;
    rendererRef.current = renderer;
    const token = {};
    activeRendererLeaseRef.current = { renderer, token };

    if (didChange) {
      rendererVersionRef.current += 1;
      resetAdaptiveFrameRate();
      retryPipeline({ resetRenderer: true });
    }

    return () => {
      if (activeRendererLeaseRef.current?.token === token) {
        activeRendererLeaseRef.current = null;
      }

      enqueueMicrotask(() => {
        if (activeRendererLeaseRef.current?.renderer === renderer) {
          return;
        }

        try {
          const returnedValue: unknown = renderer.dispose?.();
          const asyncError = createAsyncContractError(
            returnedValue,
            "MatrixEffect Renderer dispose() 必须同步完成，不能返回 Promise。",
          );

          if (asyncError !== null) {
            reportRendererDisposeFailure(asyncError);
          }
        } catch (cause) {
          reportRendererDisposeFailure(cause);
        }
      });
    };
  }, [renderer, resetAdaptiveFrameRate, retryPipeline]);

  React.useLayoutEffect(() => {
    if (mapperRef.current === mapper) {
      return;
    }

    mapperRef.current = mapper;
    retryPipeline({ resetHistory: true });
  }, [mapper, retryPipeline]);

  React.useLayoutEffect(() => {
    if (transformsRef.current === transforms) {
      return;
    }

    transformsRef.current = transforms;
    retryPipeline({ resetHistory: true });
  }, [retryPipeline, transforms]);

  React.useLayoutEffect(() => {
    if (gridConfigRef.current.signature === normalizedGrid.signature) {
      gridConfigRef.current = normalizedGrid;
      return;
    }

    gridConfigRef.current = normalizedGrid;
    retryPipeline({ resetHistory: true, resetRenderer: true });
  }, [normalizedGrid, retryPipeline]);

  React.useLayoutEffect(() => {
    if (maxDprRef.current === normalizedMaxDpr) {
      return;
    }

    maxDprRef.current = normalizedMaxDpr;
    retryPipeline({ resetRenderer: true });
  }, [normalizedMaxDpr, retryPipeline]);

  React.useLayoutEffect(() => {
    if (clearColorRef.current === clearColor) {
      return;
    }

    clearColorRef.current = clearColor;
    retryPipeline();
  }, [clearColor, retryPipeline]);

  React.useLayoutEffect(() => {
    const isSourceTransition = sourceIdentityRef.current !== source;

    if (isSourceTransition) {
      sourceIdentityRef.current = source;
      sourceEpochRef.current += 1;
      pipelineGenerationRef.current += 1;
      readyEpochRef.current = -1;
      successfulFrameRef.current = 0;
      resetPlaybackClock();
      discardSamplingResources();
      resetFrameHistory(buffersRef.current);

      if (clearRecoverableError()) {
        updateStatus("idle");
      }
    }

    let adapter: MatrixSourceAdapter;

    try {
      adapter = createMatrixSourceAdapter(source, {
        onStateChange: () => {
          if (sourceAdapterRef.current !== adapter) {
            return;
          }

          markDirty();
        },
      });
    } catch (cause) {
      handlePipelineError(
        createMatrixEffectError(
          "SOURCE_RUNTIME_ERROR",
          "MatrixEffect 初始化 Source adapter 失败。",
          true,
          cause,
        ),
      );
      return;
    }

    sourceAdapterRef.current = adapter;
    markDirty();

    return () => {
      if (sourceAdapterRef.current === adapter) {
        sourceAdapterRef.current = null;
      }

      try {
        adapter.dispose();
      } catch (cause) {
        if (isDevelopment()) {
          console.error(
            "[MatrixEffect] Source adapter dispose() 失败。",
            cause,
          );
        }
      }
    };
  }, [
    clearRecoverableError,
    discardSamplingResources,
    handlePipelineError,
    markDirty,
    resetPlaybackClock,
    source,
    updateStatus,
  ]);

  React.useEffect(() => {
    const root = rootRef.current;
    let active = true;
    let observer: ResizeObserver | null = null;

    if (root === null) {
      return;
    }

    const measure = () => {
      if (!active) {
        return;
      }

      const cssWidth = Math.max(0, root.clientWidth);
      const cssHeight = Math.max(0, root.clientHeight);
      const devicePixelRatio =
        typeof window !== "undefined" &&
        Number.isFinite(window.devicePixelRatio) &&
        window.devicePixelRatio > 0
          ? window.devicePixelRatio
          : 1;
      const previous = sizeRef.current;
      const didCssSizeChange =
        previous.cssWidth !== cssWidth || previous.cssHeight !== cssHeight;
      const didDprChange = previous.devicePixelRatio !== devicePixelRatio;
      const wasZeroSized = previous.cssWidth <= 0 || previous.cssHeight <= 0;
      const isZeroSized = cssWidth <= 0 || cssHeight <= 0;

      if (!didCssSizeChange && !didDprChange) {
        return;
      }

      sizeRef.current = { cssWidth, cssHeight, devicePixelRatio };
      clearMatrixAdaptiveFrameRateSamples(adaptiveFrameRateRef.current);

      if (wasZeroSized !== isZeroSized) {
        clearContinuousTiming();
      }

      if (didCssSizeChange) {
        resetFrameHistory(buffersRef.current);
      }

      preparedRendererKeyRef.current = null;
      pipelineGenerationRef.current += 1;
      clearRecoverableError();
      markDirty();

      if (isZeroSized) {
        cancelScheduledFrame();

        if (errorLockRef.current === null) {
          updateStatus("idle");
        }

        return;
      }
    };

    measure();

    if (typeof ResizeObserver !== "undefined") {
      try {
        observer = new ResizeObserver(measure);
        observer.observe(root);
      } catch {
        observer?.disconnect();
        observer = null;
      }
    }

    if (typeof window !== "undefined") {
      window.addEventListener("resize", measure);
    }

    return () => {
      active = false;
      observer?.disconnect();

      if (typeof window !== "undefined") {
        window.removeEventListener("resize", measure);
      }
    };
  }, [
    cancelScheduledFrame,
    clearContinuousTiming,
    clearRecoverableError,
    markDirty,
    updateStatus,
  ]);

  React.useEffect(() => {
    if (!decorative && !ariaLabel?.trim()) {
      warnOnce(
        "missing-aria-label",
        "decorative=false 时应提供 ariaLabel 描述 Canvas 内容。",
      );
    }
  }, [ariaLabel, decorative]);

  const showFallback = status === "error" && !hasEverSuccessfulFrame;
  const hasFallbackContent = showFallback && fallback != null;
  const hideCanvasFromAccessibility = decorative || hasFallbackContent;

  return (
    <div
      {...rootProps}
      ref={rootRef}
      data-slot="matrix-effect"
      className={cn("relative", className)}
      style={style}
    >
      <canvas
        ref={canvasRef}
        data-slot="matrix-effect-canvas"
        className={cn("absolute inset-0 block h-full w-full", canvasClassName)}
        aria-hidden={hideCanvasFromAccessibility ? true : undefined}
        role={!hideCanvasFromAccessibility ? "img" : undefined}
        aria-label={!hideCanvasFromAccessibility ? ariaLabel : undefined}
      />
      {hasFallbackContent ? (
        <div data-slot="matrix-effect-fallback" className="absolute inset-0">
          {fallback}
        </div>
      ) : null}
    </div>
  );
});

MatrixEffect.displayName = "MatrixEffect";

import type {
  MatrixEffectError,
  MatrixFit,
  MatrixProceduralContext,
  MatrixProceduralSource,
  MatrixSource,
  MatrixSourcePosition,
  SoftBlobSourceOptions,
} from "./types";

type MatrixRasterSource =
  | HTMLCanvasElement
  | HTMLImageElement
  | ImageBitmap
  | OffscreenCanvas;

type MatrixImageResource = HTMLImageElement | ImageBitmap;

interface NormalizedRasterOptions {
  readonly fit: MatrixFit;
  readonly positionX: number;
  readonly positionY: number;
  readonly smoothing: boolean;
  readonly background: string | null;
}

/** 内部 Source adapter 的创建选项；不会从组件公共入口导出 */
export interface MatrixSourceAdapterOptions {
  /** 异步图片从 loading 进入 ready 或 error 时触发 */
  onStateChange?: () => void;
}

/** 单次 Source 绘制的结构化结果；不会从组件公共入口导出 */
export type MatrixSourceDrawResult =
  | { readonly status: "drawn" }
  | { readonly status: "loading" }
  | { readonly status: "idle" }
  | { readonly status: "error"; readonly error: MatrixEffectError };

/** 核心管线消费的内部 Source adapter；不会从组件公共入口导出 */
export interface MatrixSourceAdapter {
  /** Source 是否需要持续绘制 */
  readonly animated: boolean;
  /** 把当前 Source 绘制到低分辨率采样上下文 */
  draw(context: MatrixProceduralContext): MatrixSourceDrawResult;
  /** 幂等释放 adapter 自己拥有的资源 */
  dispose(): void;
}

/** Raster Source 的源矩形与目标矩形；主要用于确定性几何验证 */
export interface MatrixSourceDrawRect {
  sourceX: number;
  sourceY: number;
  sourceWidth: number;
  sourceHeight: number;
  destinationX: number;
  destinationY: number;
  destinationWidth: number;
  destinationHeight: number;
}

const DRAWN_RESULT = { status: "drawn" } as const;
const LOADING_RESULT = { status: "loading" } as const;
const IDLE_RESULT = { status: "idle" } as const;
const DEFAULT_POSITION = 0.5;
const TRANSPARENT_FILL = "rgba(0, 0, 0, 0)";
const NOOP = () => {};
const HTML_IMAGE_BRANDS = ["[object HTMLImageElement]"] as const;
const IMAGE_BITMAP_BRANDS = ["[object ImageBitmap]"] as const;
const BLOB_BRANDS = ["[object Blob]", "[object File]"] as const;
const HTML_CANVAS_BRANDS = ["[object HTMLCanvasElement]"] as const;
const OFFSCREEN_CANVAS_BRANDS = ["[object OffscreenCanvas]"] as const;
const DEFAULT_BLOB_COUNT = 3;
const DEFAULT_BLOB_MIN_RADIUS = 0.2;
const DEFAULT_BLOB_MAX_RADIUS = 0.45;
const DEFAULT_BLOB_SPEED = 0.14;
const DEFAULT_BLOB_BASE_VALUE = 0.04;
const DEFAULT_BLOB_SEED = 1;
const MIN_BLOB_COUNT = 1;
const MAX_BLOB_COUNT = 6;
const MIN_BLOB_RADIUS = 0.01;
const MAX_BLOB_RADIUS = 2;
const MAX_BLOB_SPEED = 4;

interface SoftBlobParameters {
  readonly innerColor: string;
  readonly middleColor: string;
  readonly outerColor: string;
  readonly phaseX: number;
  readonly phaseY: number;
  readonly phaseRadius: number;
  readonly frequencyX: number;
  readonly frequencyY: number;
  readonly secondaryFrequency: number;
  readonly radiusFrequency: number;
}

function clamp(value: number, minimum: number, maximum: number): number {
  return Math.min(maximum, Math.max(minimum, value));
}

function normalizeFiniteNumber(
  value: number | undefined,
  fallback: number,
): number {
  return Number.isFinite(value) ? (value as number) : fallback;
}

function createSeededRandom(seed: number): () => number {
  let state = Math.trunc(seed) >>> 0;

  return () => {
    state = (state + 0x6d2b79f5) >>> 0;
    let value = state;
    value = Math.imul(value ^ (value >>> 15), value | 1);
    value ^= value + Math.imul(value ^ (value >>> 7), value | 61);
    return ((value ^ (value >>> 14)) >>> 0) / 4_294_967_296;
  };
}

function createSoftBlobParameters(
  count: number,
  seed: number,
): readonly SoftBlobParameters[] {
  const random = createSeededRandom(seed);
  const blobs: SoftBlobParameters[] = [];

  for (let index = 0; index < count; index += 1) {
    const phaseX =
      Math.PI * 2 * ((index + 0.5) / count + ((random() - 0.5) * 0.15) / count);
    const intensity = 0.58 + random() * 0.28;

    blobs.push({
      innerColor: `rgba(255, 255, 255, ${intensity})`,
      middleColor: `rgba(255, 255, 255, ${intensity * 0.62})`,
      outerColor: `rgba(255, 255, 255, ${intensity * 0.18})`,
      phaseX,
      phaseY: phaseX + Math.PI * 2 * (0.2 + random() * 0.6),
      phaseRadius: random() * Math.PI * 2,
      frequencyX: 0.72 + random() * 0.46,
      frequencyY: 0.62 + random() * 0.5,
      secondaryFrequency: 1.18 + random() * 0.54,
      radiusFrequency: 0.48 + random() * 0.32,
    });
  }

  return blobs;
}

/**
 * 创建由多个径向渐变组成的确定性柔和光团 Source
 *
 * - 光团参数在工厂创建时由 seed 一次性生成
 * - 位置和呼吸尺寸只依赖有效播放时间，暂停不会跳变
 * - 直接在低分辨率采样画布绘制，不使用 CSS blur 或额外帧循环
 *
 * @example
 * ```ts
 * const source = createSoftBlobSource({ seed: 42, speed: 0.12 });
 * ```
 */
export function createSoftBlobSource(
  options: SoftBlobSourceOptions = {},
): MatrixProceduralSource {
  const count = clamp(
    Math.floor(normalizeFiniteNumber(options.count, DEFAULT_BLOB_COUNT)),
    MIN_BLOB_COUNT,
    MAX_BLOB_COUNT,
  );
  const requestedMinimumRadius = clamp(
    normalizeFiniteNumber(options.minRadius, DEFAULT_BLOB_MIN_RADIUS),
    MIN_BLOB_RADIUS,
    MAX_BLOB_RADIUS,
  );
  const requestedMaximumRadius = clamp(
    normalizeFiniteNumber(options.maxRadius, DEFAULT_BLOB_MAX_RADIUS),
    MIN_BLOB_RADIUS,
    MAX_BLOB_RADIUS,
  );
  const minimumRadius = Math.min(
    requestedMinimumRadius,
    requestedMaximumRadius,
  );
  const maximumRadius = Math.max(
    requestedMinimumRadius,
    requestedMaximumRadius,
  );
  const speed = clamp(
    normalizeFiniteNumber(options.speed, DEFAULT_BLOB_SPEED),
    0,
    MAX_BLOB_SPEED,
  );
  const baseValue = clamp(
    normalizeFiniteNumber(options.baseValue, DEFAULT_BLOB_BASE_VALUE),
    0,
    1,
  );
  const seed = normalizeFiniteNumber(options.seed, DEFAULT_BLOB_SEED);
  const blobs = createSoftBlobParameters(count, seed);
  const baseChannel = Math.round(baseValue * 255);
  const baseColor = `rgb(${baseChannel}, ${baseChannel}, ${baseChannel})`;

  return {
    type: "procedural",
    animated: speed > 0,
    draw({ ctx, width, height, time }) {
      const shortSide = Math.min(width, height);
      const effectiveTime = Number.isFinite(time)
        ? Math.max(0, time) * speed
        : 0;

      ctx.globalAlpha = 1;
      ctx.globalCompositeOperation = "source-over";
      ctx.fillStyle = baseColor;
      ctx.fillRect(0, 0, width, height);

      for (const blob of blobs) {
        const primaryX = Math.sin(
          effectiveTime * blob.frequencyX + blob.phaseX,
        );
        const secondaryX = Math.sin(
          effectiveTime * blob.secondaryFrequency + blob.phaseY,
        );
        const primaryY = Math.sin(
          effectiveTime * blob.frequencyY + blob.phaseY,
        );
        const secondaryY = Math.sin(
          effectiveTime * (blob.secondaryFrequency * 0.83) + blob.phaseX,
        );
        const centerX = width * (0.5 + primaryX * 0.28 + secondaryX * 0.07);
        const centerY = height * (0.5 + primaryY * 0.28 + secondaryY * 0.07);
        const radiusProgress =
          0.5 +
          Math.sin(effectiveTime * blob.radiusFrequency + blob.phaseRadius) *
            0.5;
        const radius =
          shortSide *
          (minimumRadius + (maximumRadius - minimumRadius) * radiusProgress);
        const gradient = ctx.createRadialGradient(
          centerX,
          centerY,
          0,
          centerX,
          centerY,
          radius,
        );

        gradient.addColorStop(0, blob.innerColor);
        gradient.addColorStop(0.42, blob.middleColor);
        gradient.addColorStop(0.76, blob.outerColor);
        gradient.addColorStop(1, "rgba(255, 255, 255, 0)");
        ctx.fillStyle = gradient;
        ctx.fillRect(
          centerX - radius,
          centerY - radius,
          radius * 2,
          radius * 2,
        );
      }

      ctx.globalCompositeOperation = "source-over";
    },
  };
}

function createSourceError(
  code: MatrixEffectError["code"],
  message: string,
  cause?: unknown,
): MatrixEffectError {
  return {
    code,
    message,
    recoverable: true,
    ...(cause === undefined ? {} : { cause }),
  };
}

function createErrorResult(
  code: MatrixEffectError["code"],
  message: string,
  cause?: unknown,
): MatrixSourceDrawResult {
  return {
    status: "error",
    error: createSourceError(code, message, cause),
  };
}

function normalizeFit(fit: MatrixFit | undefined): MatrixFit {
  if (fit === "contain" || fit === "fill") {
    return fit;
  }

  return "cover";
}

function normalizePosition(value: number | undefined): number {
  if (!Number.isFinite(value)) {
    return DEFAULT_POSITION;
  }

  return Math.min(1, Math.max(0, value as number));
}

function normalizeRasterOptions(options: {
  fit?: MatrixFit;
  position?: MatrixSourcePosition;
  smoothing?: boolean;
  background?: string | null;
}): NormalizedRasterOptions {
  return {
    fit: normalizeFit(options.fit),
    positionX: normalizePosition(options.position?.x),
    positionY: normalizePosition(options.position?.y),
    smoothing: options.smoothing ?? true,
    background: options.background ?? null,
  };
}

function hasPositiveDimensions(width: number, height: number): boolean {
  return (
    Number.isFinite(width) && Number.isFinite(height) && width > 0 && height > 0
  );
}

function writeMatrixSourceDrawRect(
  rect: MatrixSourceDrawRect,
  sourceWidth: number,
  sourceHeight: number,
  targetWidth: number,
  targetHeight: number,
  fit: MatrixFit,
  positionX: number,
  positionY: number,
): boolean {
  if (
    !hasPositiveDimensions(sourceWidth, sourceHeight) ||
    !hasPositiveDimensions(targetWidth, targetHeight)
  ) {
    return false;
  }

  rect.sourceX = 0;
  rect.sourceY = 0;
  rect.sourceWidth = sourceWidth;
  rect.sourceHeight = sourceHeight;
  rect.destinationX = 0;
  rect.destinationY = 0;
  rect.destinationWidth = targetWidth;
  rect.destinationHeight = targetHeight;

  if (fit === "fill") {
    return true;
  }

  const scale =
    fit === "contain"
      ? Math.min(targetWidth / sourceWidth, targetHeight / sourceHeight)
      : Math.max(targetWidth / sourceWidth, targetHeight / sourceHeight);

  if (fit === "contain") {
    rect.destinationWidth = sourceWidth * scale;
    rect.destinationHeight = sourceHeight * scale;
    rect.destinationX = (targetWidth - rect.destinationWidth) * positionX;
    rect.destinationY = (targetHeight - rect.destinationHeight) * positionY;
    return true;
  }

  rect.sourceWidth = Math.min(sourceWidth, targetWidth / scale);
  rect.sourceHeight = Math.min(sourceHeight, targetHeight / scale);
  rect.sourceX = (sourceWidth - rect.sourceWidth) * positionX;
  rect.sourceY = (sourceHeight - rect.sourceHeight) * positionY;
  return true;
}

/**
 * 计算 Raster Source 在采样画布中的精确绘制矩形
 *
 * 返回值保留浮点精度；输入存在非正尺寸时返回 null。
 */
export function resolveMatrixSourceDrawRect(
  sourceWidth: number,
  sourceHeight: number,
  targetWidth: number,
  targetHeight: number,
  fit: MatrixFit = "cover",
  position?: MatrixSourcePosition,
): MatrixSourceDrawRect | null {
  const rect: MatrixSourceDrawRect = {
    sourceX: 0,
    sourceY: 0,
    sourceWidth: 0,
    sourceHeight: 0,
    destinationX: 0,
    destinationY: 0,
    destinationWidth: 0,
    destinationHeight: 0,
  };

  const didResolve = writeMatrixSourceDrawRect(
    rect,
    sourceWidth,
    sourceHeight,
    targetWidth,
    targetHeight,
    normalizeFit(fit),
    normalizePosition(position?.x),
    normalizePosition(position?.y),
  );

  return didResolve ? rect : null;
}

function resetSamplingContext(
  context: MatrixProceduralContext,
  background: string | null,
) {
  const { ctx, width, height } = context;

  ctx.setTransform(1, 0, 0, 1, 0, 0);
  ctx.globalAlpha = 1;
  ctx.globalCompositeOperation = "source-over";
  ctx.clearRect(0, 0, width, height);
  ctx.beginPath();

  if (background !== null) {
    // 先设透明基线，使非法 CSS 颜色不会继承上一次 fillStyle。
    ctx.fillStyle = TRANSPARENT_FILL;
    ctx.fillStyle = background;
    ctx.fillRect(0, 0, width, height);
  }
}

function restoreSamplingContext(
  ctx: CanvasRenderingContext2D,
  result: MatrixSourceDrawResult,
): MatrixSourceDrawResult {
  try {
    ctx.restore();
    return result;
  } catch (cause) {
    return createErrorResult(
      "SOURCE_RUNTIME_ERROR",
      "MatrixEffect 恢复采样 Canvas 状态失败。",
      cause,
    );
  }
}

function createDrawRect(): MatrixSourceDrawRect {
  return {
    sourceX: 0,
    sourceY: 0,
    sourceWidth: 0,
    sourceHeight: 0,
    destinationX: 0,
    destinationY: 0,
    destinationWidth: 0,
    destinationHeight: 0,
  };
}

function drawRasterSource(
  context: MatrixProceduralContext,
  source: MatrixRasterSource,
  sourceWidth: number,
  sourceHeight: number,
  options: NormalizedRasterOptions,
  drawRect: MatrixSourceDrawRect,
  zeroSizeResult: MatrixSourceDrawResult,
): MatrixSourceDrawResult {
  if (!hasPositiveDimensions(context.width, context.height)) {
    return IDLE_RESULT;
  }

  if (!hasPositiveDimensions(sourceWidth, sourceHeight)) {
    return zeroSizeResult;
  }

  const didResolve = writeMatrixSourceDrawRect(
    drawRect,
    sourceWidth,
    sourceHeight,
    context.width,
    context.height,
    options.fit,
    options.positionX,
    options.positionY,
  );

  if (!didResolve) {
    return zeroSizeResult;
  }

  const { ctx } = context;

  try {
    ctx.save();
  } catch (cause) {
    return createErrorResult(
      "SOURCE_RUNTIME_ERROR",
      "MatrixEffect 保存采样 Canvas 状态失败。",
      cause,
    );
  }

  let result: MatrixSourceDrawResult = DRAWN_RESULT;

  try {
    resetSamplingContext(context, options.background);
    ctx.imageSmoothingEnabled = options.smoothing;
    ctx.drawImage(
      source,
      drawRect.sourceX,
      drawRect.sourceY,
      drawRect.sourceWidth,
      drawRect.sourceHeight,
      drawRect.destinationX,
      drawRect.destinationY,
      drawRect.destinationWidth,
      drawRect.destinationHeight,
    );
  } catch (cause) {
    result = createErrorResult(
      "SOURCE_RUNTIME_ERROR",
      "MatrixEffect 绘制 Raster Source 失败。",
      cause,
    );
  }

  return restoreSamplingContext(ctx, result);
}

function hasObjectBrand(value: unknown, brands: readonly string[]): boolean {
  if (
    (typeof value !== "object" && typeof value !== "function") ||
    value === null
  ) {
    return false;
  }

  try {
    return brands.includes(Object.prototype.toString.call(value));
  } catch {
    return false;
  }
}

function isHtmlImageElement(value: unknown): value is HTMLImageElement {
  return (
    (typeof HTMLImageElement !== "undefined" &&
      value instanceof HTMLImageElement) ||
    hasObjectBrand(value, HTML_IMAGE_BRANDS)
  );
}

function isImageBitmap(value: unknown): value is ImageBitmap {
  return (
    (typeof ImageBitmap !== "undefined" && value instanceof ImageBitmap) ||
    hasObjectBrand(value, IMAGE_BITMAP_BRANDS)
  );
}

function isBlob(value: unknown): value is Blob {
  return (
    (typeof Blob !== "undefined" && value instanceof Blob) ||
    hasObjectBrand(value, BLOB_BRANDS)
  );
}

function isCanvas(
  value: unknown,
): value is HTMLCanvasElement | OffscreenCanvas {
  const isHtmlCanvas =
    (typeof HTMLCanvasElement !== "undefined" &&
      value instanceof HTMLCanvasElement) ||
    hasObjectBrand(value, HTML_CANVAS_BRANDS);
  const isOffscreenCanvas =
    (typeof OffscreenCanvas !== "undefined" &&
      value instanceof OffscreenCanvas) ||
    hasObjectBrand(value, OFFSCREEN_CANVAS_BRANDS);

  return isHtmlCanvas || isOffscreenCanvas;
}

function getImageWidth(image: MatrixImageResource): number {
  if (isHtmlImageElement(image)) {
    return image.naturalWidth;
  }

  return image.width;
}

function getImageHeight(image: MatrixImageResource): number {
  if (isHtmlImageElement(image)) {
    return image.naturalHeight;
  }

  return image.height;
}

function hasAssignedImageSource(image: HTMLImageElement): boolean {
  return image.currentSrc !== "" || image.getAttribute("src") !== null;
}

function createImageSourceAdapter(
  source: Extract<MatrixSource, { type: "image" }>,
  options: MatrixSourceAdapterOptions,
): MatrixSourceAdapter {
  const rasterOptions = normalizeRasterOptions(source);
  const onStateChange = options.onStateChange ?? NOOP;
  const drawRect = createDrawRect();
  const zeroSizeResult = createErrorResult(
    "SOURCE_RUNTIME_ERROR",
    "MatrixEffect 图片 Source 已失去可绘制尺寸。",
  );
  let image: MatrixImageResource | null = null;
  let ownedImage: HTMLImageElement | null = null;
  let objectUrl: string | null = null;
  let revokeObjectUrl: ((url: string) => void) | null = null;
  let removeListeners: (() => void) | null = null;
  let state: "loading" | "ready" | "error" = "loading";
  let errorResult: MatrixSourceDrawResult | null = null;
  let initialized = false;
  let disposed = false;

  const detachListeners = () => {
    removeListeners?.();
    removeListeners = null;
  };

  const settleError = (message: string, cause?: unknown) => {
    if (disposed || state !== "loading") {
      return;
    }

    state = "error";
    errorResult = createErrorResult("SOURCE_LOAD_FAILED", message, cause);
    detachListeners();

    if (initialized) {
      onStateChange();
    }
  };

  const settleReady = () => {
    if (disposed || state !== "loading" || image === null) {
      return;
    }

    const width = getImageWidth(image);
    const height = getImageHeight(image);

    if (!hasPositiveDimensions(width, height)) {
      settleError("MatrixEffect 图片 Source 没有可绘制尺寸。");
      return;
    }

    state = "ready";
    detachListeners();

    if (initialized) {
      onStateChange();
    }
  };

  const watchImage = (
    candidate: HTMLImageElement,
    checkCurrentState: boolean,
  ) => {
    const handleLoad = () => settleReady();
    const handleError = (event: Event) =>
      settleError(
        "MatrixEffect 图片 Source 加载失败；请检查 URL、网络和 CORS 配置。",
        event,
      );

    candidate.addEventListener("load", handleLoad);
    candidate.addEventListener("error", handleError);
    removeListeners = () => {
      candidate.removeEventListener("load", handleLoad);
      candidate.removeEventListener("error", handleError);
    };

    if (
      checkCurrentState &&
      candidate.complete &&
      (hasPositiveDimensions(candidate.naturalWidth, candidate.naturalHeight) ||
        hasAssignedImageSource(candidate))
    ) {
      settleReady();
    }
  };

  try {
    const input = source.src;

    if (typeof input === "string" || isBlob(input)) {
      if (typeof Image === "undefined") {
        settleError(
          "当前环境无法创建图片对象；请仅在客户端初始化 MatrixEffect Source。",
        );
      } else {
        ownedImage = new Image();
        image = ownedImage;

        let imageUrl: string;

        if (typeof input === "string") {
          imageUrl = input;

          if (source.crossOrigin !== undefined) {
            ownedImage.crossOrigin = source.crossOrigin;
          }
        } else if (
          typeof URL === "undefined" ||
          typeof URL.createObjectURL !== "function" ||
          typeof URL.revokeObjectURL !== "function"
        ) {
          settleError("当前环境不支持 Blob object URL，无法加载图片 Source。");
          imageUrl = "";
        } else {
          const objectUrlApi = URL;
          objectUrl = objectUrlApi.createObjectURL(input);
          revokeObjectUrl = (url) => objectUrlApi.revokeObjectURL(url);
          imageUrl = objectUrl;
        }

        if (state === "loading") {
          // new Image() 在尚未设置 src 时也可能是 complete，需在赋值后再检查。
          watchImage(ownedImage, false);
          ownedImage.src = imageUrl;

          if (state === "loading" && ownedImage.complete) {
            settleReady();
          }
        }
      }
    } else if (isHtmlImageElement(input)) {
      image = input;
      watchImage(input, true);
    } else if (isImageBitmap(input)) {
      image = input;
      settleReady();
    } else {
      settleError("MatrixEffect 收到了当前环境无法识别的图片 Source。");
    }
  } catch (cause) {
    settleError("MatrixEffect 初始化图片 Source 失败。", cause);
  }

  initialized = true;

  return {
    animated: false,
    draw(context) {
      if (disposed) {
        return IDLE_RESULT;
      }

      if (state === "loading") {
        return LOADING_RESULT;
      }

      if (state === "error" || image === null) {
        return (
          errorResult ??
          createErrorResult(
            "SOURCE_LOAD_FAILED",
            "MatrixEffect 图片 Source 不可用。",
          )
        );
      }

      const width = getImageWidth(image);
      const height = getImageHeight(image);

      return drawRasterSource(
        context,
        image,
        width,
        height,
        rasterOptions,
        drawRect,
        zeroSizeResult,
      );
    },
    dispose() {
      if (disposed) {
        return;
      }

      disposed = true;
      detachListeners();

      if (ownedImage !== null) {
        try {
          ownedImage.removeAttribute("src");
        } catch {
          // 清理失败不应破坏 Strict Mode 的后续 setup。
        }
      }

      if (objectUrl !== null && revokeObjectUrl !== null) {
        try {
          revokeObjectUrl(objectUrl);
        } catch {
          // object URL 已失效时保持 dispose 幂等。
        }

        objectUrl = null;
      }

      image = null;
      ownedImage = null;
    },
  };
}

function createCanvasSourceAdapter(
  source: Extract<MatrixSource, { type: "canvas" }>,
): MatrixSourceAdapter {
  const rasterOptions = normalizeRasterOptions(source);
  const canvasInput = source.canvas;
  const animated = source.animated ?? false;
  const drawRect = createDrawRect();
  let disposed = false;

  return {
    animated,
    draw(context) {
      if (disposed) {
        return IDLE_RESULT;
      }

      let canvas: HTMLCanvasElement | OffscreenCanvas | null;

      try {
        canvas =
          typeof canvasInput === "function" ? canvasInput() : canvasInput;
      } catch (cause) {
        return createErrorResult(
          "SOURCE_RUNTIME_ERROR",
          "MatrixEffect Canvas supplier 执行失败。",
          cause,
        );
      }

      if (canvas === null) {
        return IDLE_RESULT;
      }

      if (!isCanvas(canvas)) {
        return createErrorResult(
          "SOURCE_RUNTIME_ERROR",
          "MatrixEffect Canvas supplier 返回了不受支持的值。",
        );
      }

      return drawRasterSource(
        context,
        canvas,
        canvas.width,
        canvas.height,
        rasterOptions,
        drawRect,
        IDLE_RESULT,
      );
    },
    dispose() {
      disposed = true;
    },
  };
}

function isThenable(value: unknown): value is PromiseLike<unknown> {
  return (
    (typeof value === "object" || typeof value === "function") &&
    value !== null &&
    typeof (value as PromiseLike<unknown>).then === "function"
  );
}

function createProceduralSourceAdapter(
  source: Extract<MatrixSource, { type: "procedural" }>,
): MatrixSourceAdapter {
  const draw = source.draw;
  const animated = source.animated ?? true;
  const background = source.background ?? null;
  let disposed = false;

  return {
    animated,
    draw(context) {
      if (disposed || !hasPositiveDimensions(context.width, context.height)) {
        return IDLE_RESULT;
      }

      const { ctx } = context;

      try {
        ctx.save();
      } catch (cause) {
        return createErrorResult(
          "SOURCE_RUNTIME_ERROR",
          "MatrixEffect 保存程序化 Source 的 Canvas 状态失败。",
          cause,
        );
      }

      let result: MatrixSourceDrawResult = DRAWN_RESULT;

      try {
        resetSamplingContext(context, background);
        const returnedValue: unknown = draw(context);

        if (isThenable(returnedValue)) {
          // 适配器会同步上报契约错误，同时吸收后续 rejection，避免形成未处理 Promise。
          void Promise.resolve(returnedValue).catch(NOOP);
          result = createErrorResult(
            "SOURCE_RUNTIME_ERROR",
            "MatrixEffect 程序化 Source 必须同步完成绘制，不能返回 Promise。",
          );
        }
      } catch (cause) {
        result = createErrorResult(
          "SOURCE_RUNTIME_ERROR",
          "MatrixEffect 程序化 Source 绘制失败。",
          cause,
        );
      }

      try {
        // current path 不属于 Canvas drawing state，必须显式清理以防跨帧残留。
        ctx.beginPath();
      } catch (cause) {
        result = createErrorResult(
          "SOURCE_RUNTIME_ERROR",
          "MatrixEffect 清理程序化 Source 的 Canvas 路径失败。",
          cause,
        );
      }

      return restoreSamplingContext(ctx, result);
    },
    dispose() {
      disposed = true;
    },
  };
}

function createInvalidSourceAdapter(): MatrixSourceAdapter {
  const errorResult = createErrorResult(
    "SOURCE_RUNTIME_ERROR",
    "MatrixEffect 收到了无法识别的 Source 类型。",
  );
  let disposed = false;

  return {
    animated: false,
    draw: () => (disposed ? IDLE_RESULT : errorResult),
    dispose: () => {
      disposed = true;
    },
  };
}

/**
 * 把公共 Source 描述符规范化为核心管线可消费的内部 adapter
 *
 * adapter 创建时会快照描述符配置，但外部 Canvas 和图片的尺寸及像素仍按
 * 每次绘制时的实时值读取。调用方必须在 Source 变化或卸载时调用 dispose。
 */
export function createMatrixSourceAdapter(
  source: MatrixSource,
  options: MatrixSourceAdapterOptions = {},
): MatrixSourceAdapter {
  switch (source.type) {
    case "image":
      return createImageSourceAdapter(source, options);
    case "canvas":
      return createCanvasSourceAdapter(source);
    case "procedural":
      return createProceduralSourceAdapter(source);
    default:
      return createInvalidSourceAdapter();
  }
}

/**
 * 判断采样读取异常是否由跨域或其他 origin-clean 限制导致
 *
 * 使用错误名称而非仅依赖 instanceof DOMException，以兼容跨 realm 异常。
 */
export function isMatrixSourceSecurityError(cause: unknown): boolean {
  if (typeof cause !== "object" || cause === null) {
    return false;
  }

  try {
    return "name" in cause && cause.name === "SecurityError";
  } catch {
    return false;
  }
}

/** 把 getImageData() 异常映射为核心管线使用的结构化 Source 错误 */
export function createMatrixSourceSampleError(
  cause: unknown,
): MatrixEffectError {
  if (isMatrixSourceSecurityError(cause)) {
    return createSourceError(
      "SOURCE_SECURITY_ERROR",
      "MatrixEffect 无法读取采样 Canvas；请使用同源资源，或为远程资源配置正确的 CORS 响应。",
      cause,
    );
  }

  return createSourceError(
    "SOURCE_RUNTIME_ERROR",
    "MatrixEffect 读取采样 Canvas 失败。",
    cause,
  );
}

import type {
  LevelsTransformOptions,
  LuminanceMapperOptions,
  MatrixSignalMapper,
  MatrixSignalTransform,
  TemporalSmoothingTransformOptions,
  ThresholdTransformOptions,
} from "./types";

const REC_709_WEIGHTS = [0.2126, 0.7152, 0.0722] as const;
const warnedIssues = new Set<string>();

function warnOnce(issue: string, message: string) {
  if (
    typeof process === "undefined" ||
    process.env.NODE_ENV !== "development" ||
    warnedIssues.has(issue)
  ) {
    return;
  }

  warnedIssues.add(issue);
  console.warn(`[MatrixEffect] ${message}`);
}

function clampUnit(value: number) {
  if (value <= 0) {
    return 0;
  }

  if (value >= 1) {
    return 1;
  }

  return value;
}

function normalizeFiniteOption(
  value: number | undefined,
  fallback: number,
  issue: string,
  message: string,
) {
  if (value === undefined) {
    return fallback;
  }

  if (Number.isFinite(value)) {
    return value;
  }

  warnOnce(issue, message);
  return fallback;
}

function normalizeLuminanceWeights(
  options?: LuminanceMapperOptions,
): readonly [number, number, number] {
  const weights = options?.weights;

  if (weights === undefined) {
    return REC_709_WEIGHTS;
  }

  const [red, green, blue] = weights;
  const sum = red + green + blue;
  const isValid =
    Number.isFinite(red) &&
    Number.isFinite(green) &&
    Number.isFinite(blue) &&
    red >= 0 &&
    green >= 0 &&
    blue >= 0 &&
    Number.isFinite(sum) &&
    sum > 0;

  if (!isValid) {
    warnOnce(
      "luminance-weights",
      "亮度权重必须是三个有限非负数，且总和必须有限并大于 0；已回退到 Rec.709。",
    );
    return REC_709_WEIGHTS;
  }

  return [red / sum, green / sum, blue / sum];
}

/**
 * 创建把 RGBA 采样映射为视觉亮度的 Mapper
 *
 * - 默认使用 Rec.709 RGB 权重
 * - 合法自定义权重会在创建时归一化并快照
 * - Alpha 不参与亮度计算，也不会被修改
 *
 * @example
 * ```ts
 * const redChannelMapper = createLuminanceMapper({ weights: [1, 0, 0] });
 * ```
 */
export function createLuminanceMapper(
  options?: LuminanceMapperOptions,
): MatrixSignalMapper {
  const [redWeight, greenWeight, blueWeight] =
    normalizeLuminanceWeights(options);

  return (frame) => {
    const { rgba, values } = frame;

    for (let index = 0, rgbaIndex = 0; index < values.length; index += 1) {
      values[index] =
        (rgba[rgbaIndex] * redWeight +
          rgba[rgbaIndex + 1] * greenWeight +
          rgba[rgbaIndex + 2] * blueWeight) /
        255;
      rgbaIndex += 4;
    }
  };
}

/**
 * 创建主信号反相 Transform
 *
 * 有限值按 `1 - value` 原地转换；非有限值保留给 MatrixEffect 在整条
 * Transform 管线结束后统一归零和裁切。
 *
 * @example
 * ```ts
 * const invert = createInvertTransform();
 * ```
 */
export function createInvertTransform(): MatrixSignalTransform {
  return (frame) => {
    const { values } = frame;

    for (let index = 0; index < values.length; index += 1) {
      const value = values[index];

      if (Number.isFinite(value)) {
        values[index] = 1 - value;
      }
    }
  };
}

/**
 * 创建输入范围、Gamma、对比度和亮度 Transform
 *
 * 处理顺序固定为输入范围归一化、Gamma、对比度、亮度。工厂会在创建时
 * 快照配置；最终 `[0, 1]` 裁切由 MatrixEffect 在完整转换链后统一执行。
 *
 * @example
 * ```ts
 * const levels = createLevelsTransform({
 *   inputMin: 0.15,
 *   inputMax: 0.85,
 *   gamma: 1.2,
 *   contrast: 1.1,
 * });
 * ```
 */
export function createLevelsTransform(
  options: LevelsTransformOptions = {},
): MatrixSignalTransform {
  let inputMin = normalizeFiniteOption(
    options.inputMin,
    0,
    "levels-input-min",
    "Levels inputMin 必须是有限数；已回退到 0。",
  );
  let inputMax = normalizeFiniteOption(
    options.inputMax,
    1,
    "levels-input-max",
    "Levels inputMax 必须是有限数；已回退到 1。",
  );
  let inputSpan = inputMax - inputMin;

  if (!Number.isFinite(inputSpan) || inputSpan <= 0) {
    warnOnce(
      "levels-input-range",
      "Levels 输入范围必须具有有限且大于 0 的跨度；已回退到 0 到 1。",
    );
    inputMin = 0;
    inputMax = 1;
    inputSpan = inputMax - inputMin;
  }

  const brightness = normalizeFiniteOption(
    options.brightness,
    0,
    "levels-brightness",
    "Levels brightness 必须是有限数；已回退到 0。",
  );
  const rawContrast = normalizeFiniteOption(
    options.contrast,
    1,
    "levels-contrast-finite",
    "Levels contrast 必须是有限非负数；已回退到 1。",
  );
  const contrast = rawContrast >= 0 ? rawContrast : 1;

  if (rawContrast < 0) {
    warnOnce(
      "levels-contrast-range",
      "Levels contrast 不能为负数；已回退到 1。",
    );
  }

  const rawGamma = normalizeFiniteOption(
    options.gamma,
    1,
    "levels-gamma-finite",
    "Levels gamma 必须是有限正数；已回退到 1。",
  );
  const rawGammaExponent = 1 / rawGamma;
  const isGammaValid =
    rawGamma > 0 && Number.isFinite(rawGammaExponent) && rawGammaExponent > 0;
  const gammaExponent = isGammaValid ? rawGammaExponent : 1;

  if (!isGammaValid) {
    warnOnce(
      "levels-gamma-range",
      "Levels gamma 必须是可安全求倒数的正数；已回退到 1。",
    );
  }

  return (frame) => {
    const { values } = frame;

    for (let index = 0; index < values.length; index += 1) {
      const value = values[index];

      if (!Number.isFinite(value)) {
        continue;
      }

      let output = clampUnit((value - inputMin) / inputSpan);
      output = Math.pow(output, gammaExponent);
      output = (output - 0.5) * contrast + 0.5;
      values[index] = output + brightness;
    }
  };
}

/**
 * 创建硬阈值或带 smoothstep 过渡的 Threshold Transform
 *
 * `softness` 表示阈值两侧的过渡半宽。值等于硬阈值时归入高侧；
 * 非有限 signal 值保留给 MatrixEffect 在完整转换链后统一处理。
 *
 * @example
 * ```ts
 * const threshold = createThresholdTransform({
 *   threshold: 0.55,
 *   softness: 0.08,
 * });
 * ```
 */
export function createThresholdTransform(
  options: ThresholdTransformOptions = {},
): MatrixSignalTransform {
  const threshold = normalizeFiniteOption(
    options.threshold,
    0.5,
    "threshold-value",
    "Threshold threshold 必须是有限数；已回退到 0.5。",
  );
  const rawSoftness = normalizeFiniteOption(
    options.softness,
    0,
    "threshold-softness-finite",
    "Threshold softness 必须是有限非负数；已回退到 0。",
  );
  const softness = rawSoftness >= 0 ? rawSoftness : 0;

  if (rawSoftness < 0) {
    warnOnce(
      "threshold-softness-range",
      "Threshold softness 不能为负数；已回退到 0。",
    );
  }

  if (softness === 0) {
    return (frame) => {
      const { values } = frame;

      for (let index = 0; index < values.length; index += 1) {
        const value = values[index];

        if (Number.isFinite(value)) {
          values[index] = value >= threshold ? 1 : 0;
        }
      }
    };
  }

  return (frame) => {
    const { values } = frame;

    for (let index = 0; index < values.length; index += 1) {
      const value = values[index];

      if (!Number.isFinite(value)) {
        continue;
      }

      const normalized = clampUnit(
        0.5 + 0.5 * ((value - threshold) / softness),
      );
      values[index] = normalized * normalized * (3 - 2 * normalized);
    }
  };
}

/**
 * 创建基于上一成功帧的时间无关指数平滑 Transform
 *
 * - `responseMs` 是到达目标约 63.2% 的指数时间常数
 * - 首帧、缓冲长度变化或 responseMs=0 时保留当前帧
 * - 应放在转换链最后，并用于具有持续帧循环的动态 Source
 *
 * @example
 * ```ts
 * const smoothing = createTemporalSmoothingTransform({ responseMs: 120 });
 * ```
 */
export function createTemporalSmoothingTransform(
  options: TemporalSmoothingTransformOptions,
): MatrixSignalTransform {
  const rawResponseMs = options?.responseMs;
  const isResponseValid = Number.isFinite(rawResponseMs) && rawResponseMs >= 0;
  const responseMs = isResponseValid ? rawResponseMs : 0;

  if (!isResponseValid) {
    warnOnce(
      "temporal-response",
      "Temporal smoothing responseMs 必须是有限非负数；已按 0 处理并立即跟随当前帧。",
    );
  }

  return (frame, context) => {
    const { previousValues, values } = frame;

    if (
      responseMs === 0 ||
      previousValues === null ||
      previousValues.length !== values.length
    ) {
      return;
    }

    const deltaTime = Number.isFinite(context.deltaTime)
      ? Math.max(0, context.deltaTime)
      : 0;
    const alpha = -Math.expm1((-deltaTime * 1000) / responseMs);

    for (let index = 0; index < values.length; index += 1) {
      const current = values[index];
      const previous = previousValues[index];

      if (!Number.isFinite(current) || !Number.isFinite(previous)) {
        continue;
      }

      values[index] = previous + (current - previous) * alpha;
    }
  };
}

import type {
  AsciiRendererOptions,
  CellRendererOptions,
  DotRendererOptions,
  MatrixFrameContext,
  MatrixRenderCell,
  MatrixRenderer,
} from "./types";

const DEFAULT_DOT_COLOR = "#71717a";
const DEFAULT_DOT_RADIUS_RANGE = [0.35, 4] as const;
const DEFAULT_DOT_OPACITY_RANGE = [1, 1] as const;
const DEFAULT_ASCII_CHARACTERS = " .:-=+*#%@";
const DEFAULT_ASCII_COLOR = "#71717a";
const DEFAULT_ASCII_FONT_FAMILY =
  'ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace';
const DEFAULT_ASCII_FONT_WEIGHT = "400";
const DEFAULT_ASCII_FONT_SCALE = 1;
const DEFAULT_ASCII_FALLBACK_FONT = `400 10px ${DEFAULT_ASCII_FONT_FAMILY}`;
const FULL_CIRCLE = Math.PI * 2;
const NOOP = () => {};
const warnedIssues = new Set<string>();

function warnOnce(issue: string, message: string) {
  if (
    typeof process === "undefined" ||
    process.env.NODE_ENV !== "development" ||
    warnedIssues.has(issue)
  ) {
    return;
  }

  warnedIssues.add(issue);
  console.warn(`[MatrixEffect] ${message}`);
}

function clamp(value: number, minimum: number, maximum: number): number {
  return Math.min(maximum, Math.max(minimum, value));
}

function clampUnit(value: number): number {
  if (!Number.isFinite(value) || value <= 0) {
    return 0;
  }

  if (value >= 1) {
    return 1;
  }

  return value;
}

function normalizeRange(
  range: readonly [number, number] | undefined,
  fallback: readonly [number, number],
  minimum: number,
  maximum: number,
): readonly [number, number] {
  const requestedMinimum = Number.isFinite(range?.[0])
    ? (range?.[0] as number)
    : fallback[0];
  const requestedMaximum = Number.isFinite(range?.[1])
    ? (range?.[1] as number)
    : fallback[1];
  const normalizedMinimum = clamp(requestedMinimum, minimum, maximum);
  const normalizedMaximum = clamp(requestedMaximum, minimum, maximum);

  return normalizedMinimum <= normalizedMaximum
    ? [normalizedMinimum, normalizedMaximum]
    : [normalizedMaximum, normalizedMinimum];
}

function isThenable(value: unknown): value is PromiseLike<unknown> {
  return (
    (typeof value === "object" || typeof value === "function") &&
    value !== null &&
    typeof (value as PromiseLike<unknown>).then === "function"
  );
}

function appendCirclePath(
  ctx: CanvasRenderingContext2D,
  centerX: number,
  centerY: number,
  radius: number,
) {
  ctx.moveTo(centerX + radius, centerY);
  ctx.arc(centerX, centerY, radius, 0, FULL_CIRCLE);
}

function fillCircle(
  ctx: CanvasRenderingContext2D,
  centerX: number,
  centerY: number,
  radius: number,
) {
  ctx.beginPath();
  ctx.arc(centerX, centerY, radius, 0, FULL_CIRCLE);
  ctx.fill();
}

function resolveDotValue(
  value: number,
  valueCurve: NonNullable<DotRendererOptions["valueCurve"]>,
): number {
  const curvedValue: unknown = valueCurve(clampUnit(value));

  if (isThenable(curvedValue)) {
    void Promise.resolve(curvedValue).catch(NOOP);
    throw new TypeError(
      "MatrixEffect createDotRenderer() valueCurve 必须同步返回数值，不能返回 Promise。",
    );
  }

  return clampUnit(typeof curvedValue === "number" ? curvedValue : Number.NaN);
}

function resolveDotRadius(
  value: number,
  minimumRadius: number,
  radiusSpan: number,
  maximumCellRadius: number,
): number {
  return Math.min(maximumCellRadius, minimumRadius + radiusSpan * value);
}

interface NormalizedAsciiCharacters {
  readonly glyphs: readonly string[];
  readonly drawable: readonly boolean[];
}

function normalizeAsciiCharacters(
  characters: AsciiRendererOptions["characters"],
): NormalizedAsciiCharacters {
  let glyphs: string[];

  if (typeof characters === "string") {
    glyphs = Array.from(characters);
  } else if (characters !== undefined) {
    glyphs = Array.from(characters, (glyph) =>
      typeof glyph === "string" ? glyph : "",
    );
  } else {
    glyphs = [];
  }

  if (glyphs.length === 0) {
    if (characters !== undefined) {
      warnOnce(
        "ascii-empty-characters",
        "ASCII 字符集不能为空；已回退到默认字符集。",
      );
    }

    glyphs = Array.from(DEFAULT_ASCII_CHARACTERS);
  }

  return {
    glyphs,
    drawable: glyphs.map((glyph) => glyph.trim().length > 0),
  };
}

function normalizeAsciiFontScale(value: number | undefined): number {
  return Number.isFinite(value) && (value as number) > 0
    ? (value as number)
    : DEFAULT_ASCII_FONT_SCALE;
}

function normalizeAsciiFontWeight(value: number | string | undefined): string {
  if (typeof value === "number") {
    return Number.isFinite(value) ? String(value) : DEFAULT_ASCII_FONT_WEIGHT;
  }

  if (typeof value === "string" && value.trim().length > 0) {
    return value.trim();
  }

  return DEFAULT_ASCII_FONT_WEIGHT;
}

function normalizeAsciiFontFamily(value: string | undefined): string {
  return typeof value === "string" && value.trim().length > 0
    ? value.trim()
    : DEFAULT_ASCII_FONT_FAMILY;
}

/**
 * 创建把整帧缓冲区适配为逐单元格回调的 Renderer
 *
 * - 每个 Renderer 实例只创建一个 scratch cell，并在所有格子与帧之间复用
 * - 坐标和尺寸使用 CSS px，`u/v` 表示单元格中心的归一化坐标
 * - 回调是同步的瞬时借用，不得保存 ctx/cell，且必须配平自己的 save/restore
 * - current path 只在整帧边界清理；逐格使用路径 API 时，回调必须自行 beginPath
 *
 * @example
 * ```ts
 * const renderer = createCellRenderer((ctx, cell) => {
 *   const size = Math.min(cell.width, cell.height) * cell.value;
 *   ctx.fillRect(cell.centerX - size / 2, cell.centerY - size / 2, size, size);
 * });
 * ```
 */
export function createCellRenderer(
  drawCell: (
    ctx: CanvasRenderingContext2D,
    cell: Readonly<MatrixRenderCell>,
    context: MatrixFrameContext,
  ) => void,
  options: CellRendererOptions = {},
): MatrixRenderer {
  const cellAspectRatio =
    Number.isFinite(options.cellAspectRatio) &&
    (options.cellAspectRatio as number) > 0
      ? options.cellAspectRatio
      : undefined;
  const preferredFrameRate =
    options.preferredFrameRate === 30 || options.preferredFrameRate === 60
      ? options.preferredFrameRate
      : undefined;
  const scratchCell: MatrixRenderCell = {
    index: 0,
    column: 0,
    row: 0,
    x: 0,
    y: 0,
    centerX: 0,
    centerY: 0,
    width: 0,
    height: 0,
    u: 0,
    v: 0,
    value: 0,
    r: 0,
    g: 0,
    b: 0,
    a: 0,
  };

  return {
    ...(cellAspectRatio === undefined ? {} : { cellAspectRatio }),
    ...(preferredFrameRate === undefined ? {} : { preferredFrameRate }),
    render(ctx, frame, context) {
      const { columns, rows, rgba, values } = frame;
      const { cellWidth, cellHeight } = context;

      ctx.save();

      try {
        ctx.beginPath();

        for (let index = 0; index < values.length; index += 1) {
          const column = index % columns;
          const row = Math.floor(index / columns);
          const rgbaIndex = index * 4;
          const x = column * cellWidth;
          const y = row * cellHeight;

          scratchCell.index = index;
          scratchCell.column = column;
          scratchCell.row = row;
          scratchCell.x = x;
          scratchCell.y = y;
          scratchCell.centerX = x + cellWidth / 2;
          scratchCell.centerY = y + cellHeight / 2;
          scratchCell.width = cellWidth;
          scratchCell.height = cellHeight;
          scratchCell.u = (column + 0.5) / columns;
          scratchCell.v = (row + 0.5) / rows;
          scratchCell.value = values[index];
          scratchCell.r = rgba[rgbaIndex];
          scratchCell.g = rgba[rgbaIndex + 1];
          scratchCell.b = rgba[rgbaIndex + 2];
          scratchCell.a = rgba[rgbaIndex + 3];

          const returnedValue: unknown = drawCell(ctx, scratchCell, context);

          if (isThenable(returnedValue)) {
            void Promise.resolve(returnedValue).catch(NOOP);
            throw new TypeError(
              "MatrixEffect createCellRenderer() 回调必须同步完成，不能返回 Promise。",
            );
          }
        }
      } finally {
        try {
          ctx.beginPath();
        } finally {
          ctx.restore();
        }
      }
    },
  };
}

/**
 * 创建以主信号控制圆点半径和不透明度的 Renderer
 *
 * - 默认使用中性固定色，也可保留 Source 的原始 RGB
 * - 始终把半径限制在单元格短边的一半内
 * - Source Alpha 只与最终不透明度相乘，透明像素不会因信号反相而变实
 * - 固定色且透明度恒定时，将不透明像素批量合并到同一 Path
 *
 * @example
 * ```ts
 * const renderer = createDotRenderer({
 *   color: "#52525b",
 *   radiusRange: [0.25, 4],
 * });
 * ```
 */
export function createDotRenderer(
  options: DotRendererOptions = {},
): MatrixRenderer {
  const color = options.color ?? DEFAULT_DOT_COLOR;
  const [minimumRadius, maximumRadius] = normalizeRange(
    options.radiusRange,
    DEFAULT_DOT_RADIUS_RANGE,
    0,
    Number.MAX_SAFE_INTEGER,
  );
  const [minimumOpacity, maximumOpacity] = normalizeRange(
    options.opacityRange,
    DEFAULT_DOT_OPACITY_RANGE,
    0,
    1,
  );
  const radiusSpan = maximumRadius - minimumRadius;
  const opacitySpan = maximumOpacity - minimumOpacity;
  const valueCurve = options.valueCurve ?? ((value: number) => value);
  const usesSourceColor = color === "source";
  const hasConstantOpacity = opacitySpan === 0;

  return {
    cellAspectRatio: 1,
    preferredFrameRate: 60,
    render(ctx, frame, context) {
      const { rgba, values } = frame;
      const maximumCellRadius = Math.max(
        0,
        Math.min(context.cellWidth, context.cellHeight) / 2,
      );

      ctx.save();

      try {
        ctx.globalCompositeOperation = "source-over";
        ctx.globalAlpha = 1;
        ctx.fillStyle = DEFAULT_DOT_COLOR;

        if (!usesSourceColor) {
          ctx.fillStyle = color;
        }

        if (!usesSourceColor && hasConstantOpacity) {
          ctx.globalAlpha = minimumOpacity;
          ctx.beginPath();
          let hasOpaquePath = false;
          let hasPartialAlpha = false;

          for (let index = 0; index < values.length; index += 1) {
            const alpha = rgba[index * 4 + 3];

            if (alpha !== 255) {
              hasPartialAlpha ||= alpha > 0;
              continue;
            }

            const value = resolveDotValue(values[index], valueCurve);
            const column = index % frame.columns;
            const row = Math.floor(index / frame.columns);
            const centerX = (column + 0.5) * context.cellWidth;
            const centerY = (row + 0.5) * context.cellHeight;
            const radius = resolveDotRadius(
              value,
              minimumRadius,
              radiusSpan,
              maximumCellRadius,
            );

            if (radius <= 0 || minimumOpacity <= 0) {
              continue;
            }

            appendCirclePath(ctx, centerX, centerY, radius);
            hasOpaquePath = true;
          }

          if (hasOpaquePath) {
            ctx.fill();
          }

          if (hasPartialAlpha) {
            for (let index = 0; index < values.length; index += 1) {
              const alpha = rgba[index * 4 + 3];

              if (alpha <= 0 || alpha >= 255 || minimumOpacity <= 0) {
                continue;
              }

              const value = resolveDotValue(values[index], valueCurve);
              const column = index % frame.columns;
              const row = Math.floor(index / frame.columns);
              const centerX = (column + 0.5) * context.cellWidth;
              const centerY = (row + 0.5) * context.cellHeight;
              const radius = resolveDotRadius(
                value,
                minimumRadius,
                radiusSpan,
                maximumCellRadius,
              );

              if (radius <= 0) {
                continue;
              }

              ctx.globalAlpha = minimumOpacity * (alpha / 255);
              fillCircle(ctx, centerX, centerY, radius);
            }
          }

          return;
        }

        for (let index = 0; index < values.length; index += 1) {
          const rgbaIndex = index * 4;
          const alpha = rgba[rgbaIndex + 3];

          if (alpha <= 0) {
            continue;
          }

          const value = resolveDotValue(values[index], valueCurve);
          const column = index % frame.columns;
          const row = Math.floor(index / frame.columns);
          const centerX = (column + 0.5) * context.cellWidth;
          const centerY = (row + 0.5) * context.cellHeight;
          const radius = resolveDotRadius(
            value,
            minimumRadius,
            radiusSpan,
            maximumCellRadius,
          );
          const opacity = minimumOpacity + opacitySpan * value;

          if (radius <= 0 || opacity <= 0) {
            continue;
          }

          if (usesSourceColor) {
            ctx.fillStyle = `rgb(${rgba[rgbaIndex]} ${rgba[rgbaIndex + 1]} ${rgba[rgbaIndex + 2]})`;
          }

          ctx.globalAlpha = opacity * (alpha / 255);
          fillCircle(ctx, centerX, centerY, radius);
        }
      } finally {
        try {
          ctx.beginPath();
        } finally {
          ctx.restore();
        }
      }
    },
  };
}

/**
 * 创建把主信号映射为字符密度的 ASCII Renderer
 *
 * - 字符按从低到高密度排列，并使用 round(value * (count - 1)) 选取
 * - 支持固定色或 Source RGB，Source Alpha 作为最终覆盖率
 * - 字体指标只在 prepare() 中测量一次，逐格热路径不创建对象或测量文本
 * - 字号和坐标使用 CSS px，默认提示 0.6 单元格宽高比与 30 FPS
 *
 * @example
 * ```ts
 * const renderer = createAsciiRenderer({
 *   characters: " .:-=+*#%@",
 *   colorMode: "source",
 *   fontScale: 0.9,
 * });
 * ```
 */
export function createAsciiRenderer(
  options: AsciiRendererOptions = {},
): MatrixRenderer {
  const { glyphs, drawable } = normalizeAsciiCharacters(options.characters);
  const colorMode = options.colorMode === "source" ? "source" : "fixed";
  const color = options.color ?? DEFAULT_ASCII_COLOR;
  const backgroundColor = options.backgroundColor ?? null;
  const fontFamily = normalizeAsciiFontFamily(options.fontFamily);
  const fontWeight = normalizeAsciiFontWeight(options.fontWeight);
  const fontScale = normalizeAsciiFontScale(options.fontScale);
  let preparedFont = DEFAULT_ASCII_FALLBACK_FONT;
  let preparedBaseline: CanvasTextBaseline = "middle";
  let preparedBaselineOffset = 0;

  return {
    cellAspectRatio: 0.6,
    preferredFrameRate: 30,
    prepare(ctx, _frame, context) {
      const requestedFontSize = context.cellHeight * fontScale;
      const fontSize =
        Number.isFinite(requestedFontSize) && requestedFontSize > 0
          ? requestedFontSize
          : 10;

      ctx.save();

      try {
        ctx.font = DEFAULT_ASCII_FALLBACK_FONT;
        ctx.font = `${fontWeight} ${fontSize}px ${fontFamily}`;
        preparedFont = ctx.font;

        const metrics = ctx.measureText("M");
        const ascent = metrics.actualBoundingBoxAscent;
        const descent = metrics.actualBoundingBoxDescent;
        const hasBoundingBox =
          Number.isFinite(ascent) &&
          Number.isFinite(descent) &&
          ascent >= 0 &&
          descent >= 0 &&
          ascent + descent > 0;

        preparedBaseline = hasBoundingBox ? "alphabetic" : "middle";
        preparedBaselineOffset = hasBoundingBox ? (ascent - descent) / 2 : 0;
      } finally {
        ctx.restore();
      }
    },
    render(ctx, frame, context) {
      const { columns, rows, rgba, values } = frame;
      const { cellWidth, cellHeight, cssWidth, cssHeight } = context;
      const totalCells = Math.min(values.length, columns * rows);

      if (
        totalCells <= 0 ||
        glyphs.length === 0 ||
        cellWidth <= 0 ||
        cellHeight <= 0
      ) {
        return;
      }

      ctx.save();

      try {
        ctx.beginPath();
        ctx.globalCompositeOperation = "source-over";
        ctx.globalAlpha = 1;

        if (backgroundColor !== null) {
          ctx.fillStyle = "rgba(0, 0, 0, 0)";
          ctx.fillStyle = backgroundColor;
          ctx.fillRect(0, 0, cssWidth, cssHeight);
        }

        ctx.font = preparedFont;
        ctx.textAlign = "center";
        ctx.textBaseline = preparedBaseline;

        if (colorMode === "fixed") {
          ctx.fillStyle = DEFAULT_ASCII_COLOR;
          ctx.fillStyle = color;
        }

        let previousAlpha = -1;
        let previousSourceColor = -1;

        for (let row = 0; row < rows; row += 1) {
          const rowOffset = row * columns;

          if (rowOffset >= totalCells) {
            break;
          }

          const columnsInRow = Math.min(columns, totalCells - rowOffset);
          const centerY = (row + 0.5) * cellHeight + preparedBaselineOffset;

          for (let column = 0; column < columnsInRow; column += 1) {
            const index = rowOffset + column;
            const rgbaIndex = index * 4;
            const alpha = rgba[rgbaIndex + 3];

            if (alpha <= 0) {
              continue;
            }

            const value = clampUnit(values[index]);
            const glyphIndex = Math.round(value * (glyphs.length - 1));

            if (!drawable[glyphIndex]) {
              continue;
            }

            if (alpha !== previousAlpha) {
              ctx.globalAlpha = alpha / 255;
              previousAlpha = alpha;
            }

            if (colorMode === "source") {
              const red = rgba[rgbaIndex];
              const green = rgba[rgbaIndex + 1];
              const blue = rgba[rgbaIndex + 2];
              const sourceColor = (red << 16) | (green << 8) | blue;

              if (sourceColor !== previousSourceColor) {
                ctx.fillStyle = `rgb(${red} ${green} ${blue})`;
                previousSourceColor = sourceColor;
              }
            }

            const centerX = (column + 0.5) * cellWidth;
            ctx.fillText(glyphs[glyphIndex], centerX, centerY, cellWidth);
          }
        }
      } finally {
        try {
          ctx.beginPath();
        } finally {
          ctx.restore();
        }
      }
    },
  };
}

"use client";

import * as React from "react";

import { MatrixEffect } from "./matrix-effect";
import { createAsciiRenderer, createDotRenderer } from "./renderers";
import { createSoftBlobSource } from "./sources";
import {
  createInvertTransform,
  createLevelsTransform,
  createLuminanceMapper,
} from "./transforms";
import type {
  AsciiEffectProps,
  AsciiRendererOptions,
  DotMatrixEffectProps,
  MatrixEffectHandle,
  MatrixGridConfig,
  MatrixSignalTransform,
} from "./types";

const DEFAULT_DOT_COLOR = "#71717a";
const DEFAULT_DOT_CELL_SIZE = 10;
const DEFAULT_DOT_CELL_ASPECT_RATIO = 1;
const DEFAULT_DOT_MAX_CELLS = 10_000;
const DEFAULT_DOT_RADIUS_RANGE = [0.35, 4] as const;
const DEFAULT_DOT_OPACITY_RANGE = [1, 1] as const;
const DEFAULT_ASCII_CELL_SIZE = 10;
const DEFAULT_ASCII_CELL_ASPECT_RATIO = 0.6;
const DEFAULT_ASCII_MAX_CELLS = 6_000;
const EMPTY_TRANSFORMS: readonly MatrixSignalTransform[] = [];
const PRESET_LUMINANCE_MAPPER = createLuminanceMapper();

function createAsciiCharactersSignature(
  characters: AsciiRendererOptions["characters"],
): string | null {
  if (characters === undefined) {
    return null;
  }

  return JSON.stringify([
    typeof characters === "string" ? "string" : "array",
    characters,
  ]);
}

function parseAsciiCharactersSignature(
  signature: string | null,
): AsciiRendererOptions["characters"] {
  if (signature === null) {
    return undefined;
  }

  const [kind, characters] = JSON.parse(signature) as
    | readonly ["string", string]
    | readonly ["array", readonly string[]];

  return kind === "string" ? characters : Array.from(characters);
}

function resolveDotMatrixGridFields(
  mode: "auto" | "fixed",
  cellSize: number | undefined,
  columns: number | undefined,
  rows: number | undefined,
  cellAspectRatio: number | undefined,
  maxCells: number | undefined,
): MatrixGridConfig {
  if (mode === "fixed") {
    return {
      mode: "fixed",
      columns: columns as number,
      ...(rows === undefined ? {} : { rows }),
      cellAspectRatio: cellAspectRatio ?? DEFAULT_DOT_CELL_ASPECT_RATIO,
      maxCells: maxCells ?? DEFAULT_DOT_MAX_CELLS,
    };
  }

  return {
    mode: "auto",
    cellSize: cellSize ?? DEFAULT_DOT_CELL_SIZE,
    cellAspectRatio: cellAspectRatio ?? DEFAULT_DOT_CELL_ASPECT_RATIO,
    maxCells: maxCells ?? DEFAULT_DOT_MAX_CELLS,
  };
}

/**
 * 按 Dot 预设默认值合并局部 Grid 配置
 *
 * 该辅助函数仅用于预设实现和确定性验证，不从公共 index 导出。
 */
export function resolveDotMatrixGrid(
  grid?: MatrixGridConfig,
): MatrixGridConfig {
  const mode = grid?.mode === "fixed" ? "fixed" : "auto";

  return resolveDotMatrixGridFields(
    mode,
    mode === "auto" ? grid?.cellSize : undefined,
    mode === "fixed" ? grid?.columns : undefined,
    mode === "fixed" ? grid?.rows : undefined,
    grid?.cellAspectRatio,
    grid?.maxCells,
  );
}

function resolveAsciiMatrixGridFields(
  mode: "auto" | "fixed",
  cellSize: number | undefined,
  columns: number | undefined,
  rows: number | undefined,
  cellAspectRatio: number | undefined,
  maxCells: number | undefined,
): MatrixGridConfig {
  if (mode === "fixed") {
    return {
      mode: "fixed",
      columns: columns as number,
      ...(rows === undefined ? {} : { rows }),
      cellAspectRatio: cellAspectRatio ?? DEFAULT_ASCII_CELL_ASPECT_RATIO,
      maxCells: maxCells ?? DEFAULT_ASCII_MAX_CELLS,
    };
  }

  return {
    mode: "auto",
    cellSize: cellSize ?? DEFAULT_ASCII_CELL_SIZE,
    cellAspectRatio: cellAspectRatio ?? DEFAULT_ASCII_CELL_ASPECT_RATIO,
    maxCells: maxCells ?? DEFAULT_ASCII_MAX_CELLS,
  };
}

/**
 * 按 ASCII 预设默认值合并局部 Grid 配置
 *
 * 该辅助函数仅用于预设实现和确定性验证，不从公共 index 导出。
 */
export function resolveAsciiMatrixGrid(
  grid?: MatrixGridConfig,
): MatrixGridConfig {
  const mode = grid?.mode === "fixed" ? "fixed" : "auto";

  return resolveAsciiMatrixGridFields(
    mode,
    mode === "auto" ? grid?.cellSize : undefined,
    mode === "fixed" ? grid?.columns : undefined,
    mode === "fixed" ? grid?.rows : undefined,
    grid?.cellAspectRatio,
    grid?.maxCells,
  );
}

/**
 * DotMatrixEffect — 可直接使用的动态圆点矩阵预设
 *
 * - 未传 Source 时使用确定性柔和光团驱动连续动效
 * - 支持固定色或 Source RGB，并独立控制圆点半径与透明度
 * - 按 auto/fixed mode 字段级合并响应式网格默认值
 * - 固定执行 Luminance -> Invert -> Levels -> 额外 Transform 顺序
 * - 原样转发 MatrixEffectHandle，可获取 Canvas 或合并请求重绘
 *
 * @example
 * ```tsx
 * <DotMatrixEffect
 *   className="aspect-video w-full"
 *   color="#71717a"
 *   radiusRange={[0.25, 4]}
 * />
 * ```
 */
export const DotMatrixEffect = React.forwardRef<
  MatrixEffectHandle,
  DotMatrixEffectProps
>(function DotMatrixEffect(
  {
    source,
    blobOptions,
    color = DEFAULT_DOT_COLOR,
    backgroundColor = null,
    radiusRange = DEFAULT_DOT_RADIUS_RANGE,
    opacityRange = DEFAULT_DOT_OPACITY_RANGE,
    invert = false,
    levels,
    additionalTransforms = EMPTY_TRANSFORMS,
    grid,
    ...matrixEffectProps
  },
  ref,
) {
  const blobCount = blobOptions?.count;
  const blobMinimumRadius = blobOptions?.minRadius;
  const blobMaximumRadius = blobOptions?.maxRadius;
  const blobSpeed = blobOptions?.speed;
  const blobBaseValue = blobOptions?.baseValue;
  const blobSeed = blobOptions?.seed;
  const effectiveSource = React.useMemo(
    () =>
      source ??
      createSoftBlobSource({
        count: blobCount,
        minRadius: blobMinimumRadius,
        maxRadius: blobMaximumRadius,
        speed: blobSpeed,
        baseValue: blobBaseValue,
        seed: blobSeed,
      }),
    [
      blobBaseValue,
      blobCount,
      blobMaximumRadius,
      blobMinimumRadius,
      blobSeed,
      blobSpeed,
      source,
    ],
  );

  const minimumDotRadius = radiusRange[0];
  const maximumDotRadius = radiusRange[1];
  const minimumDotOpacity = opacityRange[0];
  const maximumDotOpacity = opacityRange[1];
  const renderer = React.useMemo(
    () =>
      createDotRenderer({
        color,
        radiusRange: [minimumDotRadius, maximumDotRadius],
        opacityRange: [minimumDotOpacity, maximumDotOpacity],
      }),
    [
      color,
      maximumDotOpacity,
      maximumDotRadius,
      minimumDotOpacity,
      minimumDotRadius,
    ],
  );

  const hasLevels = levels !== undefined;
  const levelsInputMinimum = levels?.inputMin;
  const levelsInputMaximum = levels?.inputMax;
  const levelsBrightness = levels?.brightness;
  const levelsContrast = levels?.contrast;
  const levelsGamma = levels?.gamma;
  const transforms = React.useMemo(() => {
    const nextTransforms: MatrixSignalTransform[] = [];

    if (invert) {
      nextTransforms.push(createInvertTransform());
    }

    if (hasLevels) {
      nextTransforms.push(
        createLevelsTransform({
          inputMin: levelsInputMinimum,
          inputMax: levelsInputMaximum,
          brightness: levelsBrightness,
          contrast: levelsContrast,
          gamma: levelsGamma,
        }),
      );
    }

    nextTransforms.push(...additionalTransforms);
    return nextTransforms;
  }, [
    additionalTransforms,
    hasLevels,
    invert,
    levelsBrightness,
    levelsContrast,
    levelsGamma,
    levelsInputMaximum,
    levelsInputMinimum,
  ]);

  const requestedGridMode = grid?.mode === "fixed" ? "fixed" : "auto";
  const requestedCellSize =
    requestedGridMode === "auto" ? grid?.cellSize : undefined;
  const requestedColumns =
    requestedGridMode === "fixed" ? grid?.columns : undefined;
  const requestedRows = requestedGridMode === "fixed" ? grid?.rows : undefined;
  const requestedCellAspectRatio = grid?.cellAspectRatio;
  const requestedMaxCells = grid?.maxCells;
  const resolvedGrid = React.useMemo(
    () =>
      resolveDotMatrixGridFields(
        requestedGridMode,
        requestedCellSize,
        requestedColumns,
        requestedRows,
        requestedCellAspectRatio,
        requestedMaxCells,
      ),
    [
      requestedCellAspectRatio,
      requestedCellSize,
      requestedColumns,
      requestedGridMode,
      requestedMaxCells,
      requestedRows,
    ],
  );

  return (
    <MatrixEffect
      {...matrixEffectProps}
      ref={ref}
      source={effectiveSource}
      renderer={renderer}
      mapper={PRESET_LUMINANCE_MAPPER}
      transforms={transforms}
      grid={resolvedGrid}
      clearColor={backgroundColor}
    />
  );
});

DotMatrixEffect.displayName = "DotMatrixEffect";

/**
 * AsciiEffect — 把输入 Source 转换为字符密度图形的预设
 *
 * - 接收图片、Canvas 或程序化 Source，并保留透明覆盖率
 * - 支持固定色或 Source RGB、字符集和等宽字体配置
 * - 按 auto/fixed mode 合并 0.6 宽高比与 6000 cells 默认网格
 * - 固定执行 Luminance -> Invert -> Levels -> 额外 Transform 顺序
 * - 把 backgroundColor 映射为核心清屏，并原样转发 MatrixEffectHandle
 *
 * @example
 * ```tsx
 * <AsciiEffect
 *   source={{ type: "image", src: "/source.webp", fit: "contain" }}
 *   characters=" .:-=+*#%@"
 *   className="aspect-video w-full"
 * />
 * ```
 */
export const AsciiEffect = React.forwardRef<
  MatrixEffectHandle,
  AsciiEffectProps
>(function AsciiEffect(
  {
    source,
    characters,
    colorMode,
    color,
    backgroundColor = null,
    fontFamily,
    fontWeight,
    fontScale,
    invert = false,
    levels,
    additionalTransforms = EMPTY_TRANSFORMS,
    grid,
    ...matrixEffectProps
  },
  ref,
) {
  const charactersSignature = createAsciiCharactersSignature(characters);
  const stableCharacters = React.useMemo(
    () => parseAsciiCharactersSignature(charactersSignature),
    [charactersSignature],
  );
  const renderer = React.useMemo(
    () =>
      createAsciiRenderer({
        characters: stableCharacters,
        colorMode,
        color,
        fontFamily,
        fontWeight,
        fontScale,
      }),
    [color, colorMode, fontFamily, fontScale, fontWeight, stableCharacters],
  );

  const hasLevels = levels !== undefined;
  const levelsInputMinimum = levels?.inputMin;
  const levelsInputMaximum = levels?.inputMax;
  const levelsBrightness = levels?.brightness;
  const levelsContrast = levels?.contrast;
  const levelsGamma = levels?.gamma;
  const transforms = React.useMemo(() => {
    const nextTransforms: MatrixSignalTransform[] = [];

    if (invert) {
      nextTransforms.push(createInvertTransform());
    }

    if (hasLevels) {
      nextTransforms.push(
        createLevelsTransform({
          inputMin: levelsInputMinimum,
          inputMax: levelsInputMaximum,
          brightness: levelsBrightness,
          contrast: levelsContrast,
          gamma: levelsGamma,
        }),
      );
    }

    nextTransforms.push(...additionalTransforms);
    return nextTransforms;
  }, [
    additionalTransforms,
    hasLevels,
    invert,
    levelsBrightness,
    levelsContrast,
    levelsGamma,
    levelsInputMaximum,
    levelsInputMinimum,
  ]);

  const requestedGridMode = grid?.mode === "fixed" ? "fixed" : "auto";
  const requestedCellSize =
    requestedGridMode === "auto" ? grid?.cellSize : undefined;
  const requestedColumns =
    requestedGridMode === "fixed" ? grid?.columns : undefined;
  const requestedRows = requestedGridMode === "fixed" ? grid?.rows : undefined;
  const requestedCellAspectRatio = grid?.cellAspectRatio;
  const requestedMaxCells = grid?.maxCells;
  const resolvedGrid = React.useMemo(
    () =>
      resolveAsciiMatrixGridFields(
        requestedGridMode,
        requestedCellSize,
        requestedColumns,
        requestedRows,
        requestedCellAspectRatio,
        requestedMaxCells,
      ),
    [
      requestedCellAspectRatio,
      requestedCellSize,
      requestedColumns,
      requestedGridMode,
      requestedMaxCells,
      requestedRows,
    ],
  );

  return (
    <MatrixEffect
      {...matrixEffectProps}
      ref={ref}
      source={source}
      renderer={renderer}
      mapper={PRESET_LUMINANCE_MAPPER}
      transforms={transforms}
      grid={resolvedGrid}
      clearColor={backgroundColor}
    />
  );
});

AsciiEffect.displayName = "AsciiEffect";

import type * as React from "react";

/** 图片或 Canvas 输入适配到采样画布时的缩放方式 */
export type MatrixFit = "cover" | "contain" | "fill";

/** Source 在采样画布中的归一化对齐位置 */
export interface MatrixSourcePosition {
  /** 水平位置，0 为左侧，0.5 为居中，1 为右侧 */
  x: number;
  /** 垂直位置，0 为顶部，0.5 为居中，1 为底部 */
  y: number;
}

/** MatrixEffect 支持的图片输入 */
export type MatrixImageInput = string | Blob | HTMLImageElement | ImageBitmap;

/** 图片 Source 描述符 */
export interface MatrixImageSource {
  /** Source 类型判别字段 */
  type: "image";
  /** 图片 URL、Blob、HTMLImageElement 或 ImageBitmap */
  src: MatrixImageInput;
  /**
   * 图片适配到采样画布的方式
   * @default "cover"
   */
  fit?: MatrixFit;
  /**
   * 图片裁切或留白时的对齐位置
   * @default { x: 0.5, y: 0.5 }
   */
  position?: MatrixSourcePosition;
  /**
   * 降采样时是否启用图像平滑
   * @default true
   */
  smoothing?: boolean;
  /**
   * 绘制图片前填充的采样场背景色，null 表示透明
   * @default null
   */
  background?: string | null;
  /** 远程图片的跨域请求模式 */
  crossOrigin?: "anonymous" | "use-credentials";
}

/** 外部 Canvas Source 描述符 */
export interface MatrixCanvasSource {
  /** Source 类型判别字段 */
  type: "canvas";
  /** 外部 Canvas，或按需返回当前 Canvas 的 supplier */
  canvas:
    | HTMLCanvasElement
    | OffscreenCanvas
    | (() => HTMLCanvasElement | OffscreenCanvas | null);
  /**
   * 外部 Canvas 是否会持续更新
   * @default false
   */
  animated?: boolean;
  /**
   * 外部 Canvas 适配到采样画布的方式
   * @default "cover"
   */
  fit?: MatrixFit;
  /**
   * 外部 Canvas 裁切或留白时的对齐位置
   * @default { x: 0.5, y: 0.5 }
   */
  position?: MatrixSourcePosition;
  /**
   * 降采样时是否启用图像平滑
   * @default true
   */
  smoothing?: boolean;
  /**
   * 绘制外部 Canvas 前填充的采样场背景色，null 表示透明
   * @default null
   */
  background?: string | null;
}

/** 程序化 Source 每次绘制时收到的上下文 */
export interface MatrixProceduralContext {
  /** 内部采样 Canvas 的 2D 上下文 */
  ctx: CanvasRenderingContext2D;
  /** 采样画布宽度，等于 columns */
  width: number;
  /** 采样画布高度，等于 rows */
  height: number;
  /** 当前网格列数 */
  columns: number;
  /** 当前网格行数 */
  rows: number;
  /** 动画有效播放时间，单位秒 */
  time: number;
  /** 与上一个已绘制帧的有效间隔，单位秒 */
  deltaTime: number;
  /** 当前绘制尝试的帧序号；仅在上一整帧成功后推进 */
  frame: number;
}

/** 程序化 Source 描述符 */
export interface MatrixProceduralSource {
  /** Source 类型判别字段 */
  type: "procedural";
  /**
   * 在低分辨率采样画布中同步绘制当前信号场
   *
   * 绘制上下文只在本次调用期间有效，不能返回 Promise 或异步保存后继续使用。
   */
  draw: (context: MatrixProceduralContext) => void;
  /**
   * 是否需要持续帧循环
   * @default true
   */
  animated?: boolean;
  /**
   * 调用 draw 前填充的采样场背景色，null 表示透明
   * @default null
   */
  background?: string | null;
}

/** 程序化柔和光团 Source 的配置 */
export interface SoftBlobSourceOptions {
  /**
   * 参与叠加的光团数量，小数向下取整后限制在 1 到 6
   * @default 3
   */
  count?: number;
  /**
   * 光团最小半径，相对于采样画布短边的比例，限制在 0.01 到 2
   * @default 0.2
   */
  minRadius?: number;
  /**
   * 光团最大半径，相对于采样画布短边的比例，限制在 0.01 到 2
   * @default 0.45
   */
  maxRadius?: number;
  /**
   * 光团轨迹的基础相位速度，单位为弧度/秒；限制在 0 到 4，0 表示静态 Source
   * @default 0.14
   */
  speed?: number;
  /**
   * 光团之外的基础灰度，最终限制在 0 到 1
   * @default 0.04
   */
  baseValue?: number;
  /**
   * 生成光团参数的确定性种子，小数会先截断为 32 位整数
   * @default 1
   */
  seed?: number;
}

/** MatrixEffect 支持的全部 Source 描述符 */
export type MatrixSource =
  | MatrixImageSource
  | MatrixCanvasSource
  | MatrixProceduralSource;

/** MatrixEffect 的响应式或固定网格配置 */
export type MatrixGridConfig =
  | {
      /**
       * 根据容器比例和目标单元格尺寸自动计算网格
       * @default "auto"
       */
      mode?: "auto";
      /**
       * 目标单元格宽度，单位为 CSS px
       * @default 10
       */
      cellSize?: number;
      /** 单元格宽高比（宽 / 高），默认优先采用 Renderer 提示 */
      cellAspectRatio?: number;
      /**
       * 允许的最大单元格数
       * @default 10000
       */
      maxCells?: number;
      /** 自动模式不接受固定列数 */
      columns?: never;
      /** 自动模式不接受固定行数 */
      rows?: never;
    }
  | {
      /** 使用固定列数，以及可选的固定行数 */
      mode: "fixed";
      /** 固定列数 */
      columns: number;
      /** 未传时根据容器比例和 cellAspectRatio 推导 */
      rows?: number;
      /** 单元格宽高比（宽 / 高），默认优先采用 Renderer 提示 */
      cellAspectRatio?: number;
      /**
       * 允许的最大单元格数
       * @default 10000
       */
      maxCells?: number;
      /** 固定模式不接受自动模式的目标单元格宽度 */
      cellSize?: never;
    };

/** 单帧的采样数据和主信号缓冲区 */
export interface MatrixFrame {
  /** 当前网格列数 */
  readonly columns: number;
  /** 当前网格行数 */
  readonly rows: number;
  /** 与单元格一一对应的原始 RGBA 采样数据 */
  readonly rgba: Uint8ClampedArray;
  /** 当前主信号；Mapper 和 Transform 可以原地写入 */
  readonly values: Float32Array;
  /** 上一个成功绘制帧的最终信号；首帧或缓冲重置后为 null */
  readonly previousValues: Float32Array | null;
}

/** Mapper、Transform 与 Renderer 共享的单帧运行上下文 */
export interface MatrixFrameContext {
  /** 动画有效播放时间，单位秒；暂停期间不累计 */
  readonly time: number;
  /** 与上一个已绘制帧的间隔，单位秒，并由核心限制异常大值 */
  readonly deltaTime: number;
  /** 当前绘制尝试的帧序号；仅在上一整帧成功后推进 */
  readonly frame: number;
  /** 输出 Canvas 的 CSS 宽度 */
  readonly cssWidth: number;
  /** 输出 Canvas 的 CSS 高度 */
  readonly cssHeight: number;
  /** 单元格的 CSS 宽度 */
  readonly cellWidth: number;
  /** 单元格的 CSS 高度 */
  readonly cellHeight: number;
  /** 当前输出 Canvas 使用的有效设备像素比 */
  readonly dpr: number;
}

/**
 * 把原始 RGBA 采样数据映射到主信号的同步函数
 *
 * 回调必须在本次调用中完成写入，不能返回 Promise 或异步持有 frame/context。
 */
export type MatrixSignalMapper = (
  frame: MatrixFrame,
  context: MatrixFrameContext,
) => void;

/**
 * 原地转换整帧主信号的同步函数
 *
 * 回调必须在本次调用中完成转换，不能返回 Promise 或异步持有 frame/context。
 */
export type MatrixSignalTransform = (
  frame: MatrixFrame,
  context: MatrixFrameContext,
) => void;

/** 亮度 Mapper 的配置 */
export interface LuminanceMapperOptions {
  /**
   * RGB 权重；总和有限且大于 0 的合法权重会被归一化
   * @default [0.2126, 0.7152, 0.0722]
   */
  weights?: readonly [red: number, green: number, blue: number];
}

/** Levels Transform 的配置 */
export interface LevelsTransformOptions {
  /**
   * 输入黑场位置
   * @default 0
   */
  inputMin?: number;
  /**
   * 输入白场位置
   * @default 1
   */
  inputMax?: number;
  /**
   * 最后叠加到信号的亮度偏移
   * @default 0
   */
  brightness?: number;
  /**
   * 围绕 0.5 应用的对比度倍数
   * @default 1
   */
  contrast?: number;
  /**
   * Gamma 值；大于 1 时提亮中间调
   * @default 1
   */
  gamma?: number;
}

/** Threshold Transform 的配置 */
export interface ThresholdTransformOptions {
  /**
   * 二值化阈值
   * @default 0.5
   */
  threshold?: number;
  /**
   * 阈值两侧的平滑过渡半宽，0 表示硬阈值
   * @default 0
   */
  softness?: number;
}

/** Temporal smoothing Transform 的配置 */
export interface TemporalSmoothingTransformOptions {
  /**
   * 指数响应时间常数，单位毫秒；0 表示立即跟随当前帧
   */
  responseMs: number;
}

/** MatrixEffect 的整帧 Renderer 契约 */
export interface MatrixRenderer {
  /** Renderer 建议的单元格宽高比（宽 / 高） */
  readonly cellAspectRatio?: number;
  /** Renderer 建议的自动模式目标帧率 */
  readonly preferredFrameRate?: 30 | 60;
  /**
   * 在 Canvas、网格、DPR 或 Renderer 身份变化后同步准备缓存
   *
   * ctx 指向内部 staging Canvas，并非 MatrixEffectHandle.canvas。回调不能返回
   * Promise；额外调用的 save()/restore() 必须自行配平。
   */
  prepare?(
    ctx: CanvasRenderingContext2D,
    frame: MatrixFrame,
    context: MatrixFrameContext,
  ): void;
  /**
   * 把当前整帧信号同步绘制到内部 staging Canvas
   *
   * 完整成功后核心才会提交到可见 Canvas。回调不能返回 Promise 或异步持有
   * ctx/frame/context；额外调用的 save()/restore() 必须自行配平。
   */
  render(
    ctx: CanvasRenderingContext2D,
    frame: MatrixFrame,
    context: MatrixFrameContext,
  ): void;
  /**
   * Renderer 被替换或组件真正卸载时同步释放内部资源
   *
   * 同一实例同一时刻只能由一个 MatrixEffect 独占使用；开发环境 Strict Mode
   * 的立即 cleanup/setup 会由核心合并。实现必须幂等，且不能返回 Promise。
   */
  dispose?(): void;
}

/** `createCellRenderer` 回调收到的单个单元格瞬时视图 */
export interface MatrixRenderCell {
  /** 单元格在线性缓冲区中的索引 */
  index: number;
  /** 单元格列索引 */
  column: number;
  /** 单元格行索引 */
  row: number;
  /** 单元格左上角的 CSS x 坐标 */
  x: number;
  /** 单元格左上角的 CSS y 坐标 */
  y: number;
  /** 单元格中心的 CSS x 坐标 */
  centerX: number;
  /** 单元格中心的 CSS y 坐标 */
  centerY: number;
  /** 单元格 CSS 宽度 */
  width: number;
  /** 单元格 CSS 高度 */
  height: number;
  /** 单元格中心的横向归一化坐标 */
  u: number;
  /** 单元格中心的纵向归一化坐标 */
  v: number;
  /** 当前主信号值 */
  value: number;
  /** 原始采样红色通道，范围为 0 到 255 */
  r: number;
  /** 原始采样绿色通道，范围为 0 到 255 */
  g: number;
  /** 原始采样蓝色通道，范围为 0 到 255 */
  b: number;
  /** 原始采样 Alpha 通道，范围为 0 到 255 */
  a: number;
}

/** `createCellRenderer` 的 Renderer 提示配置 */
export interface CellRendererOptions {
  /** Renderer 建议的单元格宽高比（宽 / 高） */
  cellAspectRatio?: number;
  /** Renderer 建议的自动模式目标帧率 */
  preferredFrameRate?: 30 | 60;
}

/**
 * 把 0 到 1 的主信号同步转换为 Dot 视觉强度的纯函数
 *
 * 返回值会被重新限制到 0 到 1；不能返回 Promise 或异步持有渲染帧状态。
 */
export type DotValueCurve = (value: number) => number;

/** Dot Renderer 的配置 */
export interface DotRendererOptions {
  /**
   * 固定 CSS 颜色，或使用 `"source"` 保留每个采样格的 RGB
   * @default "#71717a"
   */
  color?: string | "source";
  /**
   * 主信号从 0 到 1 时对应的半径范围，单位为 CSS px
   *
   * 实际半径还会被限制到当前单元格可容纳的范围。
   * @default [0.35, 4]
   */
  radiusRange?: readonly [minimum: number, maximum: number];
  /**
   * 主信号从 0 到 1 时对应的不透明度范围
   * @default [1, 1]
   */
  opacityRange?: readonly [minimum: number, maximum: number];
  /**
   * 在计算半径和不透明度前同步应用的纯值曲线，不能返回 Promise
   * @default value => value
   */
  valueCurve?: DotValueCurve;
}

/** ASCII Renderer 的配置 */
export interface AsciiRendererOptions {
  /**
   * 从低视觉密度到高视觉密度排列的字符集
   *
   * 字符串按 Unicode code point 拆分；数组中的每个成员视为一个完整 glyph。
   * 空字符串或空数组回退默认字符集。
   * @default " .:-=+*#%@"
   */
  characters?: string | readonly string[];
  /**
   * 使用统一固定色，或保留每个采样格的 Source RGB
   * @default "fixed"
   */
  colorMode?: "fixed" | "source";
  /**
   * 固定色模式下的 CSS 颜色
   * @default "#71717a"
   */
  color?: string;
  /**
   * Renderer 绘制字符前填充的背景色，null 表示不额外填充
   *
   * 该背景在 MatrixEffect 的 clearColor 之后使用 source-over 绘制：
   * 不透明色会覆盖 clearColor，半透明色会与其叠加。
   * @default null
   */
  backgroundColor?: string | null;
  /**
   * Canvas 文本使用的字体族
   * @default "ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New', monospace"
   */
  fontFamily?: string;
  /**
   * Canvas 文本使用的字重
   * @default 400
   */
  fontWeight?: number | string;
  /**
   * 字号相对于单元格高度的比例；非有限或小于等于 0 时回退默认值
   * @default 1
   */
  fontScale?: number;
}

/** MatrixEffect 支持的目标帧率模式 */
export type MatrixFrameRate = "auto" | 30 | 60;

/** MatrixEffect 对系统减少动态效果偏好的处理方式 */
export type MatrixReducedMotion = "freeze" | "ignore";

/** MatrixEffect 的低频生命周期状态 */
export type MatrixEffectStatus = "idle" | "loading" | "ready" | "error";

/** MatrixEffect 上报给调用方的结构化错误 */
export interface MatrixEffectError {
  /** 错误所属的管线阶段 */
  code:
    | "SOURCE_LOAD_FAILED"
    | "SOURCE_SECURITY_ERROR"
    | "CANVAS_CONTEXT_UNAVAILABLE"
    | "SOURCE_RUNTIME_ERROR"
    | "MAPPER_RUNTIME_ERROR"
    | "TRANSFORM_RUNTIME_ERROR"
    | "RENDERER_RUNTIME_ERROR";
  /** 面向开发者的错误说明 */
  message: string;
  /** Source 或配置变化后是否允许自动重试 */
  recoverable: boolean;
  /** 原始异常或错误值 */
  cause?: unknown;
}

/** MatrixEffect 通过 ref 暴露的命令式句柄 */
export interface MatrixEffectHandle {
  /** 当前输出 Canvas；挂载完成前为 null */
  readonly canvas: HTMLCanvasElement | null;
  /** 标记 dirty 并请求合并重绘一帧 */
  invalidate(): void;
}

/** MatrixEffect 核心组件的属性 */
export interface MatrixEffectProps extends Omit<
  React.HTMLAttributes<HTMLDivElement>,
  "children" | "dangerouslySetInnerHTML" | "onError"
> {
  /** 输入图片、外部 Canvas 或程序化信号场 */
  source: MatrixSource;
  /** 把最终主信号绘制到输出 Canvas 的 Renderer */
  renderer: MatrixRenderer;
  /**
   * 把原始 RGBA 数据写入主信号的 Mapper
   * @default createLuminanceMapper()
   */
  mapper?: MatrixSignalMapper;
  /**
   * 按数组顺序执行的整帧信号转换链
   * @default []
   */
  transforms?: readonly MatrixSignalTransform[];
  /**
   * 响应式或固定网格配置
   * @default { mode: "auto", cellSize: 10, maxCells: 10000 }
   */
  grid?: MatrixGridConfig;
  /**
   * 是否允许动态 Source 连续播放
   * @default true
   */
  playing?: boolean;
  /**
   * 固定或自动目标帧率
   * @default "auto"
   */
  frameRate?: MatrixFrameRate;
  /**
   * 输出 Canvas 使用的最大设备像素比
   * @default 2
   */
  maxDpr?: number;
  /**
   * 组件离开视口后是否暂停连续绘制
   * @default true
   */
  pauseWhenOffscreen?: boolean;
  /**
   * 系统偏好减少动态效果时的处理方式
   * @default "freeze"
   */
  reducedMotion?: MatrixReducedMotion;
  /**
   * Renderer 执行前的输出 Canvas 清屏颜色，null 表示透明
   * @default null
   */
  clearColor?: string | null;
  /** 输出 Canvas 的 className */
  canvasClassName?: string;
  /**
   * 是否把输出 Canvas 标记为纯装饰内容
   * @default true
   */
  decorative?: boolean;
  /** decorative=false 时用于描述 Canvas 内容的无障碍标签 */
  ariaLabel?: string;
  /** 尚无成功帧且组件发生错误时显示的替代内容 */
  fallback?: React.ReactNode;
  /** 生命周期状态变化时触发 */
  onStatusChange?: (status: MatrixEffectStatus) => void;
  /** 每个 Source 首次成功绘制后触发 */
  onReady?: () => void;
  /** 发生结构化 Source 或管线错误时触发 */
  onError?: (error: MatrixEffectError) => void;
}

/** DotMatrixEffect 圆点矩阵预设的属性 */
export interface DotMatrixEffectProps extends Omit<
  MatrixEffectProps,
  "source" | "renderer" | "mapper" | "transforms" | "clearColor"
> {
  /**
   * 自定义输入 Source；未传时使用内置柔和光团 Source
   * @default createSoftBlobSource(blobOptions)
   */
  source?: MatrixSource;
  /** 内置柔和光团 Source 的配置；传入 source 时忽略 */
  blobOptions?: SoftBlobSourceOptions;
  /**
   * 固定 CSS 颜色，或使用 `"source"` 保留每个采样格的 RGB
   * @default "#71717a"
   */
  color?: string | "source";
  /**
   * 输出 Canvas 的清屏颜色，null 表示透明
   * @default null
   */
  backgroundColor?: string | null;
  /**
   * 主信号从 0 到 1 时对应的半径范围，单位为 CSS px
   * @default [0.35, 4]
   */
  radiusRange?: readonly [minimum: number, maximum: number];
  /**
   * 主信号从 0 到 1 时对应的不透明度范围
   * @default [1, 1]
   */
  opacityRange?: readonly [minimum: number, maximum: number];
  /**
   * 是否在 Levels 之前反转主信号
   * @default false
   */
  invert?: boolean;
  /** 可选的输入范围、Gamma、对比度和亮度调整 */
  levels?: LevelsTransformOptions;
  /**
   * 在预设 Invert 和 Levels 之后按顺序执行的额外 Transform
   * @default []
   */
  additionalTransforms?: readonly MatrixSignalTransform[];
}

/** AsciiEffect 字符艺术预设的属性 */
export interface AsciiEffectProps extends Omit<
  MatrixEffectProps,
  "source" | "renderer" | "mapper" | "transforms" | "clearColor" | "grid"
> {
  /** 必填的图片、外部 Canvas 或程序化输入 Source */
  source: MatrixSource;
  /**
   * 响应式或固定网格配置
   * @default { mode: "auto", cellSize: 10, cellAspectRatio: 0.6, maxCells: 6000 }
   */
  grid?: MatrixGridConfig;
  /**
   * 从低视觉密度到高视觉密度排列的字符集
   *
   * 字符串按 Unicode code point 拆分；数组中的每个成员视为一个完整 glyph。
   * 空字符串或空数组回退默认字符集。
   * @default " .:-=+*#%@"
   */
  characters?: string | readonly string[];
  /**
   * 使用统一固定色，或保留每个采样格的 Source RGB
   * @default "fixed"
   */
  colorMode?: "fixed" | "source";
  /**
   * 固定色模式下的 CSS 颜色
   * @default "#71717a"
   */
  color?: string;
  /**
   * 输出 Canvas 的清屏颜色，null 表示透明
   * @default null
   */
  backgroundColor?: string | null;
  /**
   * Canvas 文本使用的字体族
   * @default "ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New', monospace"
   */
  fontFamily?: string;
  /**
   * Canvas 文本使用的字重
   * @default 400
   */
  fontWeight?: number | string;
  /**
   * 字号相对于单元格高度的比例；非有限或小于等于 0 时回退默认值
   * @default 1
   */
  fontScale?: number;
  /**
   * 是否在 Levels 之前反转主信号
   * @default false
   */
  invert?: boolean;
  /** 可选的输入范围、Gamma、对比度和亮度调整 */
  levels?: LevelsTransformOptions;
  /**
   * 在预设 Invert 和 Levels 之后按顺序执行的额外 Transform
   * @default []
   */
  additionalTransforms?: readonly MatrixSignalTransform[];
}
